    ; SED; CLC; LDA #$09; ADC #$01 -> A=$10, C=0.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    sed
    clc
    lda #$09
    adc #$01
    cld
    cmp #$10
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
