; A7.04 — Decimal V (golden)
; provenance: Contested (V in decimal mode is undefined; ares/bsnes/Mesen2 share a convention, which is agreement, not authority)
.proc test_a7_04
    .a16
    .i16
    ; SED; CLC; LDA #$99; ADC #$01 -> A=$00 with carry out. The A result is documented and
    ; is checked; V is NOT — it is captured and reported as a variant instead.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    sed
    clc
    lda #$99
    adc #$01
    cld
    php
    pla               ; stash P before the compare clobbers it
    sta f:$7E0060
    txa
    ; Re-run to get A back for the documented half of the check.
    sed
    clc
    lda #$99
    adc #$01
    cld
    cmp #$00
    beq :+
    jmp @fail1
  :
    ; Now branch on the observed V bit (P bit 6) and report it as a variant.
    lda f:$7E0060
    and #$40
    beq :+
    lda #$03          ; variant 1 = V observed SET   ((1<<1)|1)
    sta f:$7EE010
    jml test_restore
    :
    lda #$05          ; variant 2 = V observed CLEAR ((2<<1)|1)
    sta f:$7EE010
    jml test_restore
@fail1:
    ; decimal ADC $99+$01 did not produce $00
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A8.01 — MVN fwd, A=$FFFF
; provenance: Documented (WDC datasheet)
.proc test_a8_01
    .a16
    .i16
    ; Copy 4 bytes within bank $7E using MVN; A must end at $FFFF.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$11
    sta f:$7E2000
    lda #$22
    sta f:$7E2001
    lda #$33
    sta f:$7E2002
    lda #$44
    sta f:$7E2003
    rep #$30
    .a16
    .i16
    ldx #$2000
    ldy #$2100
    lda #$0003        ; count-1
    mvn #$7E,#$7E    ; literal bank numbers; `mvn $7E,$7E` would mean bank $00
    phk
    plb               ; MVN left DBR = destination bank; restore for later reads
    cmp #$FFFF
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda f:$7E2100
    cmp #$11
    beq :+
    jmp @fail2
  :
    lda f:$7E2103
    cmp #$44
    beq :+
    jmp @fail3
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; MVN did not leave A = $FFFF
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; MVN did not copy the first byte
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; MVN did not copy the last byte
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
.endproc

; A8.02 — MVN sets DBR=dest
; provenance: Documented (SNESdev Errata, 65C816 section)
.proc test_a8_02
    .a16
    .i16
    ; After MVN $7E,$7E the data bank register is the destination bank ($7E), not $00.
    rep #$30
    .a16
    .i16
    ldx #$2000
    ldy #$2100
    lda #$0000        ; one byte
    mvn #$7E,#$7E    ; literal bank numbers; `mvn $7E,$7E` would mean bank $00
    phb
    sep #$20
    .a8
    pla
    cmp #$7E
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; MVN did not leave DBR = destination bank
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A8.03 — MVP copies backward
; provenance: Documented (WDC datasheet)
.proc test_a8_03
    .a16
    .i16
    ; MVP walks X and Y downward; point them at the LAST byte of each block.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$AA
    sta f:$7E2200
    lda #$BB
    sta f:$7E2201
    rep #$30
    .a16
    .i16
    ldx #$2201
    ldy #$2301
    lda #$0001        ; two bytes
    mvp #$7E,#$7E    ; literal bank numbers; `mvp $7E,$7E` would mean bank $00
    phk
    plb
    sep #$20
    .a8
    lda f:$7E2300
    cmp #$AA
    beq :+
    jmp @fail1
  :
    lda f:$7E2301
    cmp #$BB
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; MVP did not copy the low byte
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; MVP did not copy the high byte
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; A9.01 — BIT imm vs abs
; provenance: Documented (WDC datasheet)
.proc test_a9_01
    .a16
    .i16
    ; BIT #imm must leave N and V untouched; BIT dp must set them from the operand.
    ; BIT has no long-addressing mode, so the operand is staged in the direct page
    ; (DP = $0000, so dp $50 is $00:0050, the low-WRAM mirror of $7E:0050).
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$C0
    sta f:$7E0050
    ; Clear N and V, then BIT #$00 — Z should set, N/V must stay clear.
    clv
    lda #$01
    bit #$00
    php
    pla
    and #$C0          ; N and V
    cmp #$00
    beq :+
    jmp @fail1
  :
    ; Now BIT dp against $C0 — both N and V must set.
    lda #$FF
    bit $50
    php
    pla
    and #$C0
    cmp #$C0
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; BIT #imm wrongly modified N or V
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; BIT dp did not set N and V from memory bits 7/6
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; A9.02 — XBA swaps A halves
; provenance: Documented (WDC datasheet)
.proc test_a9_02
    .a16
    .i16
    ; XBA is always a 16-bit operation on C, regardless of the m flag.
    rep #$30
    .a16
    .i16
    lda #$1234
    xba
    cmp #$3412
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; XBA did not swap the accumulator halves
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A1.06 — TCD/TDC always 16-bit
; provenance: Documented (WDC datasheet; SNESdev Wiki, 65C816)
.proc test_a1_06
    .a16
    .i16
    ; Set D with m=1, read it back with m=0. D is restored before the assertion because a
    ; failing path would otherwise leave every direct-page access in the battery relocated.
    rep #$30
    .a16
    .i16
    phk
    plb
    lda #$1234
    sep #$20          ; m=1: an 8-bit accumulator must not narrow the transfer
    .a8
    tcd
    rep #$20
    .a16
    tdc
    sta f:$7E0114
    lda #$0000
    tcd               ; restore D BEFORE asserting
    lda f:$7E0114
    cmp #$1234
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; TCD/TDC narrowed to 8 bits under m=1 (they are always 16-bit)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A5.07 — RMW abs,X is flat
; provenance: Documented (WDC datasheet; undisbeliever's timing tables)
.proc test_a5_07
    .a16
    .i16
    ; Same instruction, once without a page cross and once with. The index must be 8-BIT: a
    ; 16-bit index makes the penalty unconditional, which is what A5.02 establishes.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$10
    .i8
    ldx #$00
    jsr hv_begin
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$10
    .i8
    ldx #$FF          ; $1234 + $FF = $1333 — crosses into the next page
    jsr hv_begin
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$8000
    bcc :+
    eor #$FFFF
    inc a             ; negate: take the magnitude
  :
    cmp #$0003
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; RMW abs,X paid a page-cross penalty (its cost is flat)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A6.09 — BRK sets B in pushed P
; provenance: Documented (WDC datasheet; SNESdev Wiki, 65C816 interrupts)
.proc test_a6_09
    .a16
    .i16
    ; The handler recovers the pushed P through the stack. In emulation BRK pushes PCH, PCL,
    ; P — so P is the last byte written, at $01:(S+1), and TSX gives S's low byte.
    jmp @start
@handler:
    tsx
    lda a:$0101,x     ; the pushed status byte
    sta f:$7E009A
    rti
@start:
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_BRK_VEC
    sep #$20
    .a8
    lda #$00
    sta f:$7E009A     ; poison, so a handler that never runs cannot pass
    sec
    xce               ; -> emulation
    .a8
    .i8
    brk
    .byte $EA
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    sep #$20
    .a8
    lda f:$7E009A
    and #$10
    cmp #$10
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; BRK did not set the B flag in the status byte it pushed
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A5.08 — A5.22 cycle spot checks
; provenance: Documented (WDC/GTE/VLSI instruction-operation tables agree on these rows; docs/accuracysnes-timing-oracle.md)
.proc test_a5_08
    .a16
    .i16
    ; Differential against NOP, 16 repeats, so no span approaches the 341-dot line wrap.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; --- baseline: 16 NOPs ---
    jsr hv_begin
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0090
    ; record slot 0: 16 NOP, absolute
    sta f:$7EE200
    ; --- XBA: +6 clocks each over NOP, so +24 dots over 16 ---
    sep #$20
    .a8
    jsr hv_begin
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 1: 16 XBA, absolute
    sta f:$7EE202
    sec
    sbc f:$7E0090
    ; record slot 2: 16 XBA - 16 NOP
    sta f:$7EE204
    cmp #$0016
    bcs :+
    jmp @fail1
  :
    cmp #$001B
    bcc :+
    jmp @fail1
  :
    ; --- REP #$00: 2 bytes, so +8 clocks each, +32 dots over 16. Emitted as raw bytes so the
    ; generator's width tracker is not told the accumulator changed size.
    sep #$20
    .a8
    jsr hv_begin
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 3: 16 REP #$00, absolute
    sta f:$7EE206
    sec
    sbc f:$7E0090
    ; record slot 4: 16 REP #$00 - 16 NOP
    sta f:$7EE208
    cmp #$001E
    bcs :+
    jmp @fail2
  :
    cmp #$0023
    bcc :+
    jmp @fail2
  :
    ; --- PHD+PLD: 30 + 36 = 66 clocks per pair against 2 NOPs at 28, so +76 dots over 8 ---
    sep #$20
    .a8
    jsr hv_begin
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 5: 8x (PHD+PLD), absolute
    sta f:$7EE20A
    sec
    sbc f:$7E0090
    ; record slot 6: 8x (PHD+PLD) - 16 NOP
    sta f:$7EE20C
    cmp #$004A
    bcs :+
    jmp @fail3
  :
    cmp #$004F
    bcc :+
    jmp @fail3
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; XBA did not cost 3 cycles (1 more than NOP)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; REP #imm did not cost 3 cycles / 2 accesses
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; PHD/PLD did not cost 4 and 5 cycles with 3 accesses each
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
.endproc

; A9.03 — E=1 R-M-W modify write
; provenance: Contested (WDC note (17) asserts RWB is low during the modify cycle in emulation mode; the GTE and VLSI renderings of the same table are silent)
.proc test_a9_03
    .a16
    .i16
    ; Seed OAM words 0 and 1, aim the port at word 0, then do one R-M-W on $2104 in emulation
    ; mode. The OAM address counter afterwards reports how many writes actually happened.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; --- seed two words so a stray second write is visible, and clear the probe ---
    stz $2102
    stz $2103
    lda #$11
    sta $2104
    lda #$99       ; NOT $22 — see the collision note below
    sta $2104
    lda #$33
    sta $2104
    lda #$44
    sta $2104
    ; --- aim at word 0 and perform ONE read-modify-write on the data port ---
    stz $2102
    stz $2103
    sec
    xce               ; -> emulation
    .a8
    .i8
    inc a:$2104       ; R-M-W on the write-sensitive OAM data port
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    ; --- how far did the address counter move? rewind and count back ---
    sep #$20
    .a8
    stz $2102
    stz $2103
    lda $2138
    sta f:$7E0130     ; byte 0 after the R-M-W
    lda $2138
    sta f:$7E0131     ; byte 1
    ; A single write advances the port by one byte; a modify-cycle write advances it by two.
    ; Byte 1 still holding its seed means one write; overwritten means two.
    lda f:$7E0131
    cmp #$99
    bne @two
    lda #$03          ; variant 1 = one write — the modify cycle did not write
    sta f:$7EE010
    jml test_restore
@two:
    lda #$05          ; variant 2 = two writes — WDC note (17) holds
    sta f:$7EE010
    jml test_restore
.endproc

; A1.07 — TCS/TXS set no flags
; provenance: Documented (WDC 65C816 datasheet; 6502.org 65c816opcodes)
.proc test_a1_07
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    ; TCS: hand it the stack pointer's own value, so S is unchanged and PHP still lands in RAM.
    tsc               ; A = S, which is $1FFF: bit 15 clear, non-zero
    sep #$80          ; N = 1, and SEP writes P directly without touching A
    bit #$0000        ; Z = 1, and BIT #imm touches nothing else
    tcs               ; the instruction under test
    php
    sep #$20
    .a8
    pla
    and #$82          ; N and Z together
    cmp #$82
    beq :+
    jmp @fail1
  :
    ; Both flags, not just Z: S is $1FFF, whose own flags are N clear and Z clear, so each of
    ; the two is planted at the value a flag-setting transfer would have to change.
    ; TXS, the same way: X gets S's own value first.
    rep #$30
    .a16
    .i16
    tsx               ; X = S
    sep #$80          ; N = 1
    bit #$0000        ; Z = 1
    txs               ; the instruction under test
    php
    sep #$20
    .a8
    pla
    and #$82
    cmp #$82
    beq :+
    jmp @fail2
  :
    ; The control: TXA is an ordinary transfer and MUST set N and clear Z.
    rep #$30
    .a16
    .i16
    ldx #$8000
    rep #$80          ; N = 0, so a transfer that sets flags has to set it
    bit #$0000        ; Z = 1, so a transfer that sets flags has to clear it
    txa               ; A = $8000: negative, non-zero
    php
    sep #$20
    .a8
    pla
    and #$82          ; N and Z together
    cmp #$80
    beq :+
    jmp @fail3
  :
    rep #$30
    .a16
    .i16
    rep #$80          ; leave N as the battery found it
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; TCS changed N or Z, so it set flags from the value transferred — the stack pointer is not data and moving a value into it describes nothing
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; TXS changed N or Z, so it set flags from the value transferred
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; TXA did not set N and clear Z from $8000, so this core sets no transfer flags at all and the two assertions above say nothing
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
.endproc

; A9.04 — ORA [d] is 24-bit
; provenance: Documented (WDC 65C816 datasheet; the Super Mario World case, SNESdev Wiki)
.proc test_a9_04
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    lda #$0000
    tcd               ; DP = 0, so the pointer lives at $00:0060
    ; Pointer -> $00:8005, bank $00's signature byte.
    lda #$8005
    sta $60
    sep #$30
    .a8
    .i8
    lda #$00
    sta $60+2      ; the bank byte
    lda #$00
    ora [$60]
    cmp #$A0
    beq :+
    jmp @fail1
  :
    ; Now the same pointer with bank $01. A (d)-style fetch through DBR still reads $A0 here.
    lda #$01
    sta $60+2
    lda #$00
    ora [$60]
    cmp #$A1
    beq :+
    jmp @fail2
  :
    ; And it really is an OR: $0F in the accumulator survives into the result.
    lda #$0F
    ora [$60]
    cmp #$AF
    beq :+
    jmp @fail3
  :
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; ORA [d] through a pointer at $00:8005 did not read bank $00's signature byte
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; ORA [d] did not read bank $01's signature through a pointer whose third byte is $01, so the effective address was not built from that byte
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; ORA [d] replaced the accumulator instead of OR-ing into it, so the two readings above were loads and say nothing about ORA
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
.endproc

; A2.11 — (dp,X) pointer wraps
; provenance: Documented (6502.org 65c816opcodes; superfamicom.org addressing modes)
.proc test_a2_11
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    ; Plant the two possible destinations before touching D: $A0 -> $5A, $A1 -> $3C.
    sep #$20
    .a8
    lda #$5A
    sta a:$00A0       ; where bank $00's pointer aims
    lda #$3C
    sta a:$00A1       ; where bank $01's pointer would aim
    ; D = $FFFF, X = $8000, operand $06: $FFFF + $06 + $8000 = $18005, wrapping to $00:8005.
    rep #$30
    .a16
    .i16
    lda #$FFFF
    tcd
    ldx #$8000
    sep #$20
    .a8
    lda ($06,X)
    sta f:$7E0132     ; stash before restoring D, which needs a 16-bit A
    rep #$30
    .a16
    .i16
    lda #$0000
    tcd               ; restore D BEFORE asserting, or every later dp access is relocated
    sep #$20
    .a8
    lda f:$7E0132
    cmp #$5A
    beq :+
    jmp @fail1
  :
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; (dp,X) fetched its pointer from bank $01 — reading $3C means the pointer address was allowed to carry out of bank $00 instead of wrapping inside it
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A7.05 — N/Z valid in decimal
; provenance: Documented (WDC 65C816 datasheet; 6502.org 65c816opcodes decimal notes)
.proc test_a7_05
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sed
    ; $99 + $01 = $00 in decimal, $9A in binary. Z is set only for the decimal answer.
    clc
    lda #$99
    adc #$01
    php
    sta f:$7E0133
    pla
    and #$02          ; Z
    sta f:$7E0134
    ; $79 + $79 = $58 in decimal, $F2 in binary. N is clear only for the decimal answer.
    clc
    lda #$79
    adc #$79
    php
    sta f:$7E0135
    pla
    and #$80          ; N
    sta f:$7E0136
    cld               ; decimal off before anything else runs
    lda f:$7E0133
    cmp #$00
    beq :+
    jmp @fail1
  :
    lda f:$7E0134
    cmp #$02
    beq :+
    jmp @fail2
  :
    lda f:$7E0135
    cmp #$58
    beq :+
    jmp @fail3
  :
    lda f:$7E0136
    cmp #$00
    beq :+
    jmp @fail4
  :
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; SED: $99 + $01 did not give $00, so the BCD addition itself is wrong
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; Z was clear after a decimal $99 + $01 = $00, so the flags describe the binary sum $9A — the NMOS 6502's behaviour, which the 65C816 does not have
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; SED: $79 + $79 did not give $58, so the BCD addition itself is wrong
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
@fail4:
    ; N was set after a decimal $79 + $79 = $58, so the flags describe the binary sum $F2
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jml test_restore
.endproc

; A6.10 — Emulation COP vector
; provenance: Documented (WDC 65C816 datasheet, vector table; SNESdev Wiki vectors)
.proc test_a6_10
    .a16
    .i16
    jmp @start
    ; Both handlers run in EMULATION mode, so ca65 has to be told the registers are 8 bits
    ; wide here. Without it the test body's own `.a16` state is still in force, `lda #$E0`
    ; assembles as three bytes, the CPU takes two, and the third ($00) is executed as a BRK.
    ; The first draft of this test did exactly that and reported neither handler.
    .a8
    .i8
    ; The emulation handler: the one that must run. RTI here is an emulation-mode RTI, pulling
    ; three bytes, which is correct because the interrupt was taken in emulation mode.
@handler_e:
    lda #$E0
    sta f:$7E0094
    rti
    ; And the native handler, installed and reachable, so taking the wrong table is a wrong
    ; ANSWER rather than a hang. It is entered in emulation mode too — the mode is decided by
    ; the COP, not by which vector was used — so its RTI returns just as cleanly; the marker it
    ; leaves behind is the whole of its job.
@handler_n:
    lda #$B0
    sta f:$7E0094
    rti
    .a16
    .i16
@start:
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$00
    sta f:$7E0094
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler_e)
    sta a:V_COP_VEC_E   ; reached through $FFF4
    lda #.LOWORD(@handler_n)
    sta a:V_COP_VEC     ; reached through $FFE4 — the wrong one from emulation mode
    sec
    xce               ; -> emulation
    .a8
    .i8
    ; Raw bytes rather than `cop #$00`: ca65 2.19, which CI installs, rejects the immediate
    ; form as an illegal addressing mode. See A6.02.
    .byte $02, $00    ; cop #$00
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda f:$7E0094
    cmp #$E0
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; COP in emulation mode did not vector through $FFF4 — the $B0 marker means it took the native table's $FFE4 instead, and $00 means it reached neither handler
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A8.04 — MVN encodes dest first
; provenance: Documented (WDC 65C816 datasheet, opcode table; 6502.org 65c816opcodes)
.proc test_a8_04
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    ; Seed the byte a swapped decode would read, and the destination it would leave alone.
    sep #$20
    .a8
    lda #$3C
    sta f:$7E8005     ; what `read from bank $7E` would find
    lda #$5A
    sta f:$7E0300     ; the destination, so 'untouched' is distinguishable too
    ; MVN of one byte: X = source offset, Y = destination offset, A = count - 1.
    rep #$30
    .a16
    .i16
    ldx #$8005
    ldy #$0300
    lda #$0000        ; one byte
    ; $54 then DESTINATION then SOURCE. Written as bytes so this tests the core's decoding
    ; rather than ca65's operand order — which is `mvn <src>,<dest>`, so `mvn #$00,#$7E`
    ; assembles to exactly these three bytes. Checked by assembling it, not assumed.
    .byte $54, $7E, $00
    phk
    plb               ; MVN leaves DBR = destination bank; restore it before reading back
    sep #$20
    .a8
    lda f:$7E0300
    cmp #$A0
    beq :+
    jmp @fail1
  :
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; MVN read its operands in mnemonic order rather than machine order — $3C means source and destination were swapped, and $5A means the move did not happen at all
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A1.08 — CLC/XCE is a no-op
; provenance: Documented (WDC datasheet: XCE exchanges carry and E, nothing else)
.proc test_a1_08
    .a16
    .i16
    ; Plant distinguishable 16-bit values in all three registers, then execute the no-op XCE.
    rep #$30
    .a16
    .i16
    lda #$1234
    ldx #$5678
    ldy #$9ABC
    clc
    xce               ; C=0 in, E=0 out: nothing should change
    ; Stash A before the status check, because reading P costs a PLA into the accumulator. A
    ; core that truncated A to its low byte would otherwise be invisible: the PLA overwrites
    ; the evidence before anything compares it.
    sta f:$7E0094
    ; Widths next: if m or x were disturbed the comparisons below would be 8-bit and could
    ; pass on the low byte alone.
    php
    sep #$20
    .a8
    pla
    ; Keep bit 0: the carry is half of what XCE exchanges, so discarding it would let a core
    ; that leaves C set pass a test whose entire claim is that nothing changed.
    and #$31
    cmp #$00
    beq :+
    jmp @fail1
  :
    rep #$30
    .a16
    .i16
    lda f:$7E0094
    cmp #$1234
    beq :+
    jmp @fail2
  :
    cpx #$5678
    beq :+
    jmp @fail3
  :
    cpy #$9ABC
    beq :+
    jmp @fail4
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; CLC/XCE in native mode disturbed the m/x width bits or the carry
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; CLC/XCE in native mode disturbed A
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; CLC/XCE in native mode disturbed X
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
@fail4:
    ; CLC/XCE in native mode disturbed Y
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jml test_restore
.endproc

; A1.09 — REP cannot widen in E=1
; provenance: Documented (WDC datasheet; SNESdev Errata, 65C816 section)
.proc test_a1_09
    .a16
    .i16
    ; Enter emulation, attempt to widen both registers, then leave.
    rep #$30
    .a16
    .i16
    sec
    xce               ; -> emulation
    .a8
    .i8
    rep #$30           ; must be ignored: E=1 pins m=x=1
    .a16
    .i16
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    ; Native again. If REP had taken effect, m and x would now be 0.
    php
    pla
    and #$30
    cmp #$30
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; REP #$30 cleared m/x while E=1
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A8.05 — MVN index wrap
; provenance: Documented (WDC datasheet: the block-move indices are bank offsets)
.proc test_a8_05
    .a16
    .i16
    ; X starts at the top of the source bank, Y in the middle of the destination bank.
    rep #$30
    .a16
    .i16
    ldx #$FFFF
    ldy #$1000
    lda #$0001        ; count-1: two bytes moved
    mvn #$7E,#$7E    ; literal bank numbers; `mvn $7E,$7E` would mean bank $00
    phk
    plb               ; MVN left DBR = $7E
    cpx #$0001
    beq :+
    jmp @fail1
  :
    cpy #$1002
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; X did not wrap inside the source bank
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; Y did not advance independently of X
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; A1.10 — PLP cannot widen in E=1
; provenance: Documented (WDC datasheet: m/x are forced while E=1, whatever writes P)
.proc test_a1_10
    .a16
    .i16
    rep #$30
    .a16
    .i16
    sec
    xce               ; -> emulation
    .a8
    .i8
    ; Pull a P with m/x clear (bits 5 and 4) but I still set.
    lda #$04
    pha
    plp               ; must not widen anything: E=1 pins m=x=1
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    php
    pla
    and #$30
    cmp #$30
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; PLP cleared m/x while E=1
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A4.07 — JML [a] 24-bit dest
; provenance: Documented (WDC datasheet; SNESdev Errata, 65C816 section)
.proc test_a4_07
    .a16
    .i16
    ; Build a 24-bit pointer at $00:1000 (low WRAM mirror): offset = @landed, bank = $80.
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@landed)
    sta f:$7E1000
    sep #$20
    .a8
    lda #$80
    sta f:$7E1002
    jml [$1000]
@landed:
    ; PHK reports the bank actually being executed from.
    phk
    pla
    cmp #$80
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; JML [a] ignored the pointer's bank byte
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A2.12 — [dp],Y bank carry
; provenance: Documented (SNESdev Errata, 65C816 section; anomie's addressing notes)
.proc test_a2_12
    .a16
    .i16
    ; $7F:0001 is where the bank carry must land; $7E:0001 is where a masking core looks.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$3C
    sta f:$7F0001
    lda #$C3
    sta f:$7E0001
    ; Direct page $10..$12 holds the 24-bit pointer $7E:FFFF; Y = 2.
    rep #$30
    .a16
    .i16
    lda #$0000
    tcd
    lda #$FFFF
    sta f:$7E0010
    sep #$20
    .a8
    lda #$7E
    sta f:$7E0012
    rep #$10
    .i16
    ldy #$0002
    ; DBR is deliberately left alone: [dp],Y must ignore it and use the pointer's bank.
    lda [$10],y
    cmp #$3C
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; [dp],Y did not carry into the next bank — $C3 means it masked to 16 bits
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A4.09 — PC wraps in bank
; provenance: Documented (WDC datasheet; SNESdev Errata, 65C816 section)
.proc test_a4_09
    .a16
    .i16
    ; Assemble the wrapped instruction stream into bank $7E as data.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$A9          ; LDA #imm
    sta f:$7EFFFF
    lda #$5A          ; the immediate, at the WRAPPED address
    sta f:$7E0000
    lda #$A5          ; what a bank-carrying core would fetch instead
    sta f:$7F0000
    ; JML back to bank $00, assembled by hand: 5C lo hi bank.
    lda #$5C
    sta f:$7E0001
    rep #$20
    .a16
    lda #.LOWORD(@landed)
    sta f:$7E0002
    sep #$20
    .a8
    lda #$00
    sta f:$7E0004
    ; Enter the stream. A is 8-bit, so the LDA there takes a one-byte operand.
    jml $7EFFFF
@landed:
    cmp #$5A
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; PC carried into the next bank on the operand fetch — $A5 means it read $7F:0000
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A4.10 — Branch wrap (golden)
; provenance: Contested (upstream marks the relative addressing modes r/rl "XXX: untested"; no source vouches for the bank-boundary case)
.proc test_a4_10
    .a16
    .i16
    ; BRA at the top of bank $7E, displacement +$10.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$80          ; BRA
    sta f:$7EFFFD
    lda #$10          ; +16 from $FFFF
    sta f:$7EFFFE
    ; Seed both landing sites with a long jump home.
    lda #$5C
    sta f:$7E000F
    sta f:$7F000F
    rep #$20
    .a16
    lda #.LOWORD(@wrapped)
    sta f:$7E0010
    lda #.LOWORD(@carried)
    sta f:$7F0010
    sep #$20
    .a8
    lda #$00
    sta f:$7E0012
    sta f:$7F0012
    jml $7EFFFD
    @wrapped:
    sep #$20
    .a8
    lda #$03          ; variant 1 = wrapped inside the bank (documented)
    sta f:$7EE010
    jml test_restore
    @carried:
    sep #$20
    .a8
    lda #$05          ; variant 2 = carried into the next bank
    sta f:$7EE010
    jml test_restore
.endproc

; A8.06 — E=1 confines MVN offsets
; provenance: Documented (WDC datasheet: E=1 forces x=1, so the indices are 8-bit)
.proc test_a8_06
    .a16
    .i16
    ; Seed the two candidate second-source bytes distinctly, and clear the destination.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$11
    sta f:$7E00FF     ; first source byte
    lda #$22
    sta f:$7E0000     ; second source IF the offset wraps inside page 0
    lda #$33
    sta f:$7E0100     ; second source if the offset grew past $FF
    lda #$00
    sta f:$7E0050
    sta f:$7E0051
    ; The count lives in the full 16-bit C, which cannot be loaded in emulation mode, so set
    ; it first: XCE changes the index width, not C.
    rep #$30
    .a16
    .i16
    lda #$0001        ; count-1: two bytes
    sec
    xce               ; -> emulation
    .a8
    .i8
    ldx #$FF          ; one byte short of the page end
    ldy #$50
    mvn #$7E,#$7E    ; literal bank numbers; `mvn $7E,$7E` would mean bank $00
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    phk
    plb               ; MVN left DBR = $7E
    lda f:$7E0050
    cmp #$11
    beq :+
    jmp @fail1
  :
    lda f:$7E0051
    cmp #$22
    beq :+
    jmp @fail2
  :
    ; --- the destination index, which the move above never takes past $FF ---
    ; Without this half a core with a 16-bit Y passes on the source assertion alone: Y only ran
    ; from $50 to $52 there and never reached its own boundary.
    lda #$44
    sta f:$7E0060
    lda #$55
    sta f:$7E0061
    lda #$00
    sta f:$7E0000     ; cleared: this is where a confined destination offset wraps to
    sta f:$7E0100     ; and this is where an unconfined one would write
    rep #$30
    .a16
    .i16
    lda #$0001        ; count-1: two bytes
    sec
    xce               ; -> emulation
    .a8
    .i8
    ldx #$60
    ldy #$FF          ; one byte short of the page end
    mvn #$7E,#$7E
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    phk
    plb
    lda f:$7E00FF
    cmp #$44
    beq :+
    jmp @fail3
  :
    lda f:$7E0000
    cmp #$55
    beq :+
    jmp @fail4
  :
    lda f:$7E0100
    cmp #$00
    beq :+
    jmp @fail5
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the first block-move byte did not arrive
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; the source offset was not confined to $00xx — $33 means it advanced to $0100
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; the first destination byte did not arrive
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
@fail4:
    ; the destination offset was not confined to $00xx — it wrote past the page instead
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jml test_restore
@fail5:
    ; the destination offset advanced to $0100 instead of wrapping inside page 0
    sep #$20
    .a8
    lda #$0A
    sta f:$7EE010
    jml test_restore
.endproc

; A3.08 — JSR (a,X) escapes page 1
; provenance: Documented (WDC datasheet; superfamicom.org escape list)
.proc test_a3_08
    .a16
    .i16
    ; The subroutine, jumped over. It leaves emulation, rebuilds the stack, and rejoins.
    bra @body
@sub:
    clc
    xce               ; -> native
    rep #$30
    .a16
    .i16
    .a16
    .i16
    lda f:V_SAVED_S
    tcs
    jmp @after
@body:
    ; Canary at the top of the stack page: a wrapped second push lands exactly here.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$EE
    sta f:$7E01FF
    ; Seed $00FF with the COMPLEMENT of the byte the push must deliver. Left as stale WRAM it
    ; could already hold that byte, and the positive check below would then pass for a core
    ; that never made the second push at all -- an outcome dependent on test order.
    lda #(<(@after-1)) ^ $FF
    sta f:$7E00FF
    ; Pointer for the indirect jump, in low WRAM (mirrored at $00:0210).
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@sub)
    sta f:$7E0210
    ; E=1, S=$0100: the first push lands at $0100, the second must escape to $00FF.
    lda #$0100
    tcs
    sec
    xce               ; -> emulation
    .a8
    .i8
    ldx #$00
    jsr ($0210,x)
@after:
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda f:$7E01FF
    cmp #$EE
    beq :+
    jmp @fail1
  :
    ; The canary alone is vacuous: a core that pushed one byte, or none, would also leave
    ; $01FF untouched. So check the escaped byte positively — $00FF must hold the LOW half of
    ; the pushed return address, which JSR defines as (@after - 1).
    ; 
    ; S cannot serve as the control here: emulation mode forces the stack's high byte back to
    ; $01 at the next instruction boundary, so S reads $01FE whether the push escaped or not.
    ; 
    ; The expected byte is computed by the assembler rather than written out, so this pins the
    ; relationship and not the ROM layout — which is why the value itself is still not named.
    lda f:$7E00FF
    sec
    sbc #<(@after-1)
    cmp #$00
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; JSR (a,X) wrapped its second push into page 1 and clobbered $01FF, instead of escaping to $00FF
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; the second return-address byte did not land at $00FF — JSR (a,X) pushed fewer bytes than it should, or put them elsewhere
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; A3.06 — (d,S),Y escape + carry
; provenance: Documented (WDC datasheet; superfamicom.org escape list)
.proc test_a3_06
    .a16
    .i16
    ; Seed all three candidate results distinctly.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$5A
    sta f:$7F0001     ; escaped pointer + bank carry: the documented answer
    lda #$99
    sta f:$7E0001     ; escaped pointer, but the bank carry masked away
    lda #$77
    sta f:$7E0302     ; pointer read confined to page 1, then + Y
    ; Two pointers: the one at the escaped address, and the one a confined core would find.
    rep #$30
    .a16
    .i16
    lda #$FFFF
    sta f:$7E0202     ; at S+d = $01FE+$04, escaping page 1
    lda #$0300
    sta f:$7E0102     ; at ($FE+$04) & $FF, inside page 1
    ; DBR first — PHA/PLB uses the stack, so do it before S is parked at the boundary.
    sep #$20
    .a8
    lda #$7E
    pha
    plb
    rep #$30
    .a16
    .i16
    lda #$01FE
    tcs
    sec
    xce               ; -> emulation
    .a8
    .i8
    ldy #$02
    lda ($04,s),y
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    cmp #$5A
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; (d,S),Y misread: $77 = pointer confined to page 1, $99 = bank carry masked to 16 bits
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A5.09 — +1 m width penalty
; provenance: Documented (WDC/GTE/VLSI instruction-operation tables; docs/accuracysnes-timing-oracle.md)
.proc test_a5_09
    .a16
    .i16
    ; Same instruction, same address, twice: once 8-bit, once 16-bit.
    rep #$30
    .a16
    .i16
    phk
    plb
    ; --- m=1: LDA abs moves one byte ---
    sep #$20
    .a8
    jsr hv_begin
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0096
    ; record slot 116: 16x LDA abs, m=1
    sta f:$7EE2E8
    ; --- m=0: the same LDA moves two ---
    rep #$20
    .a16
    jsr hv_begin
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    lda $0000
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 117: 16x LDA abs, m=0
    sta f:$7EE2EA
    sec
    sbc f:$7E0096
    ; record slot 118: 16x (m=0 - m=1), expect 32
    sta f:$7EE2EC
    cmp #$001E
    bcs :+
    jmp @fail1
  :
    cmp #$0023
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; LDA abs did not cost one extra 8-clock access with m=0
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

