; A6.11 — WAI wakes, no vector
; provenance: Documented (WDC datasheet: WAI wakes on the interrupt line; I gates the vector)
.proc test_a6_11
    .a16
    .i16
    ; The handler must NOT run. It sets a flag so its running is observable.
    bra @body
@handler:
    sep #$20
    .a8
    .a8
    lda #$01
    sta f:$7E0142
    lda $4211        ; acknowledge so the line drops
    rti
@body:
    rep #$30
    .a16
    .i16
    phk
    plb
    rep #$20
    .a16
    lda #@handler
    sta a:V_IRQ_VEC
    sep #$20
    .a8
    lda #$00
    sta f:$7E0142     ; handler-ran flag, clear
    lda #200
    sta $4207
    stz $4208         ; HTIME = 200
    lda $4211         ; clear any stale latch
    sei               ; I = 1: the IRQ is masked, so it must not vector
    lda #$10
    sta $4200         ; H-IRQ enabled
    wai
    ; --- resumed in line, or we never got here ---
    lda $4211
    sta f:$7E0144     ; stash: reading $4211 clears the latch
    stz $4200         ; disarm before asserting; a failure exits immediately
    lda f:$7E0144
    and #$80
    cmp #$80
    beq :+
    jmp @fail1
  :
    lda f:$7E0142
    cmp #$00
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; WAI returned with no IRQ pending — it fell through instead of waiting
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; WAI with I=1 vectored to the handler instead of resuming in line
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; A8.07 — MVN interruptible
; provenance: Documented (WDC datasheet: MVN rewinds PC by 3 per iteration, so RTI re-enters)
.proc test_a8_07
    .a16
    .i16
    ; The NMI handler counts invocations and acknowledges RDNMI.
    bra @body
@nmi:
    ; Preserve A/X/Y. RTI restores P, PC and PBR — NOT the registers — and for THIS test that
    ; is load-bearing rather than hygiene: MVN keeps its remaining byte count in A and its
    ; offsets in X and Y, so a handler that clobbers them makes the move resume wrong. The
    ; first version of this test omitted the pushes and lost the tail of the block, which read
    ; exactly like the resume-short defect the test exists to detect.
    rep #$30
    .a16
    .i16
    .a16
    .i16
    pha
    phx
    phy
    sep #$20
    .a8
    .a8
    lda f:$7E0150
    inc a
    sta f:$7E0150
    ; LONG addressing, and this is not tidiness: MVN sets DBR to its DESTINATION bank while it
    ; runs, so an interrupt taken mid-move enters the handler with DBR = $7F. Absolute `lda
    ; $4210` would read WRAM at $7F:4210 instead of acknowledging RDNMI, the NMI line would
    ; stay asserted, and the handler would re-enter until the move starved.
    lda f:$004210     ; acknowledge RDNMI
    rep #$30
    .a16
    .i16
    .a16
    .i16
    ply
    plx
    pla
    rti
@body:
    rep #$30
    .a16
    .i16
    phk
    plb
    rep #$20
    .a16
    lda #@nmi
    sta a:V_NMI_VEC
    ; Seed only the three source bytes that get checked, and clear their destinations so
    ; 'arrived' is distinguishable from 'was already there'.
    sep #$20
    .a8
    lda #$00
    sta f:$7E0150     ; NMI count
    lda #$A1
    sta f:$7E2000     ; source offset 0
    lda #$B2
    sta f:$7E3000     ; source offset 4096
    lda #$C3
    sta f:$7E3FFF     ; source offset 8191 — the last byte moved
    lda #$00
    sta f:$7F0000
    sta f:$7F1000
    sta f:$7F1FFF
    ; Arm VBlank NMI. NMI ignores the I flag, so no CLI is needed.
    lda #$80
    sta $4200
    ; 8192 bytes from $7E:2000 to $7F:0000. Emitted raw: the machine encoding is
    ; 54 <dest> <src>, the reverse of how the mnemonic reads (A8.04 asserts exactly this).
    rep #$30
    .a16
    .i16
    ldx #$2000
    ldy #$0000
    lda #$1FFF        ; count-1
    .byte $54, $7F, $7E
    phk
    plb               ; MVN left DBR = $7F
    sep #$20
    .a8
    stz $4200         ; disarm before asserting; a failure exits immediately
    lda $4210         ; clear any pending RDNMI latch
    ; Half one: the interrupt actually happened. Without this the copy check below is
    ; satisfied just as well by a core that never took an NMI at all.
    ; Normalise any non-zero count to 1: how MANY NMIs land depends on where in the frame the
    ; move started, which is not something the cart fixes, so only 'at least one' is asserted.
    lda f:$7E0150
    beq :+
    lda #$01
    :
    cmp #$01
    beq :+
    jmp @fail1
  :
    ; Half two: every part of the block arrived, the last byte most of all.
    lda f:$7F0000
    cmp #$A1
    beq :+
    jmp @fail2
  :
    lda f:$7F1000
    cmp #$B2
    beq :+
    jmp @fail3
  :
    lda f:$7F1FFF
    cmp #$C3
    beq :+
    jmp @fail4
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; no NMI fired during the block move — the copy check below proves nothing without it
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; the first byte of the block move did not arrive
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; the middle of the block move did not arrive
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
@fail4:
    ; the LAST byte did not arrive — MVN resumed short after the interrupt
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jml test_restore
.endproc

; A6.12 — WAI wake lat (golden)
; provenance: Contested (the stated 1-cycle latency is 1.5 dots, below what a cart can resolve; recorded in buckets rather than asserted)
.proc test_a6_12
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei               ; masked: WAI must wake without vectoring (A6.11)
    lda #200
    sta $4207
    stz $4208         ; HTIME = 200
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ enabled
    wai
    ; Latch H as the very first thing after resuming — every instruction here is latency.
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213C
    xba
    lda $213C
    and #$01
    xba
    rep #$20
    .a16
    and #$01FF
    ; record slot 122: H latched immediately after WAI resumed
    sta f:$7EE2F4
    sec
    sbc #200          ; minus HTIME: the wake latency in dots
    ; record slot 123: WAI wake latency (dots)
    sta f:$7EE2F6
    ; Disarm before reporting; a failing path would exit immediately.
    sep #$20
    .a8
    stz $4200
    lda $4211
    ; Report in 4-dot buckets: 1 cycle is 1.5 dots, so the exact value is not resolvable and
    ; a variant claiming otherwise would be measuring the latch sequence, not the wake.
    rep #$20
    .a16
    lda f:$7EE2F6     ; the latency recorded above
    lsr a
    lsr a
    sep #$20
    .a8
    and #$3F
    asl a
    ora #$01
    sta f:$7EE010
    jml test_restore
.endproc

; A4.11 — JMP (a,X) ptr bank
; provenance: Documented (SNESdev Errata, 65C816 section (worked example PBR=$05))
.proc test_a4_11
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    ; Install the continuation both stubs return through, as a 24-bit pointer.
    lda #.LOWORD(@landed)
    sta a:V_BANKPROBE_RET
    sep #$20
    .a8
    lda #^@landed
    sta a:V_BANKPROBE_RET+2
    ; Poison the result so 'neither stub ran' is distinguishable from either answer.
    lda #$FF
    sta a:V_BANKPROBE
    rep #$30
    .a16
    .i16
    ldx #$800A        ; $FFFE + $800A = $1_8008, wrapping to $8008 in the program bank
    jmp ($FFFE,x)
@landed:
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda a:V_BANKPROBE
    cmp #$00
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; JMP (a,X) did not take its pointer from the program bank: $01 = carried into bank $01, $FF = neither stub ran
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

