    rep #$30
    .a16
    .i16
    ldx #$800A        ; $FFFE + $800A = $1_8008, wrapping to $8008 in the program bank
    jsr ($FFFE,x)
@landed:
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda a:V_BANKPROBE
    cmp #$00
    beq :+
