; A6.13 — IRQ handler PBR = $00
; provenance: Documented (WDC datasheet: the vector is 16-bit, so the handler runs in bank 0)
.proc test_a6_13
    .a16
    .i16
    bra @body
@handler:
    rep #$30
    .a16
    .i16
    pha
    sep #$20
    .a8
    .a8
    ; PHK pushes the CURRENT program bank, which is the whole question.
    phk
    pla
    sta f:$7E0190
    lda $4211         ; acknowledge
    lda #$01
    sta f:$7E0192     ; release the spin loop
    rep #$30
    .a16
    .i16
    .a16
    .i16
    pla
    rti
@body:
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    rep #$20
    .a16
    lda #@handler
    sta a:V_IRQ_VEC
    ; Poison the result: $FF distinguishes 'the handler never ran' from either bank.
    sep #$20
    .a8
    lda #$FF
    sta f:$7E0190
    lda #$00
    sta f:$7E0192
    ; Assemble the spin stub into bank $7E. It must live outside bank $00 for this test to
    ; mean anything -- see the note above.
    lda #$AF
    sta f:$7E3000     ; LDA long
    lda #$92
    sta f:$7E3001
    lda #$01
    sta f:$7E3002
    lda #$7E
    sta f:$7E3003     ; ...$7E0192, the rendezvous flag
    lda #$F0
    sta f:$7E3004     ; BEQ
    lda #$FA
    sta f:$7E3005     ; -6: back to the LDA
    lda #$5C
    sta f:$7E3006     ; JML
    rep #$20
    .a16
    lda #.LOWORD(@after)
    sta f:$7E3007
    sep #$20
    .a8
    lda #$00
    sta f:$7E3009     ; ...back into bank $00
    ; Arm an H-IRQ, unmask, and run the stub. The interrupt lands with PBR = $7E.
    lda #200
    sta $4207
    stz $4208         ; HTIME = 200
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ enabled
    cli
    jml $7E3000
@after:
    sep #$20
    .a8
    sei
    stz $4200
    lda $4211
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda f:$7E0190
    cmp #$00
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the interrupt handler did not run with PBR = $00 — $7E means the program bank was left as the interrupted code's, $FF that the handler never ran at all
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A6.14 — RTI pull matches mode
; provenance: Documented (WDC datasheet: RTI pulls PBR in native mode only)
.proc test_a6_14
    .a16
    .i16
    bra @body
@brkh:
    ; The handler does nothing but return: this row is about RTI's pull count, and any work
    ; here would need its own register discipline to stay out of the way of that.
    rti
@body:
    rep #$30
    .a16
    .i16
    phk
    plb
    rep #$20
    .a16
    lda #@brkh
    sta a:V_BRK_VEC
    ; Park the stack somewhere unambiguous inside page 1, then drop to emulation mode.
    lda #$01F0
    tcs
    sec
    xce               ; -> emulation
    .a8
    .i8
    tsc
    sta f:$7E01A0     ; S before the interrupt (low byte; SH is pinned to $01 here)
    brk
    .byte $EA         ; BRK's signature byte, skipped by the pushed PC+2
    tsc
    sta f:$7E01A2     ; S after RTI returned
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; Equal means RTI pulled exactly what the interrupt pushed. One higher means it also took
    ; a PBR byte that emulation mode never pushed.
    lda f:$7E01A0
    cmp f:$7E01A2
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; emulation-mode RTI did not restore S — it pulled a different number of bytes than the interrupt pushed
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; A2.13 — 16-bit dp page cross
; provenance: Contested (superfamicom.org describes the wrap as happening "theoretically"; the dossier records the row as UNVERIFIED, so it is observed rather than asserted)
.proc test_a2_13
    .a16
    .i16
    ; Seed the shared low byte and both candidate high bytes.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$34
    sta f:$7E10FF     ; the low byte, agreed by every reading
    lda #$12
    sta f:$7E1100     ; high byte if the sum continues
    lda #$AB
    sta f:$7E1000     ; high byte if the offset wraps inside the page
    ; D = $1000, then a 16-bit read from dp offset $FF.
    rep #$30
    .a16
    .i16
    lda #$1000
    tcd
    lda $FF
    sta f:$7E01B0
    ; Restore D BEFORE anything else: a moved direct page relocates every later dp access.
    lda #$0000
    tcd
    phk
    plb
    lda f:$7E01B0
    ; record slot 120: A2.05 the 16-bit value read across the page boundary
    sta f:$7EE2F0
    cmp #$1234
    bne :+
    sep #$20
    .a8
    lda #$03          ; variant 1 = continued into $1100
    sta f:$7EE010
    jml test_restore
    :
    rep #$20
    .a16
    lda f:$7E01B0
    cmp #$AB34
    bne :+
    sep #$20
    .a8
    lda #$05          ; variant 2 = wrapped back to $1000
    sta f:$7EE010
    jml test_restore
    :
    sep #$20
    .a8
    lda #$07          ; variant 3 = neither; the raw value is in slot 120
    sta f:$7EE010
    jml test_restore
.endproc

; B1.01 — MEMSEL selects FastROM
; provenance: Documented (SNESdev Wiki, Memory map / timing; fullsnes)
.proc test_b1_01
    .a16
    .i16
    ; 32 long reads from bank $80, once slow and once fast. 2 master clocks saved per access
    ; over 32 accesses is 64 clocks = 16 dots, comfortably outside the measurement jitter.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $420D         ; MEMSEL = 0: banks $80+ run at 8 clocks
    jsr hv_begin
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$20
    .a8
    lda #$01
    sta $420D         ; MEMSEL = 1: FastROM, 6 clocks
    jsr hv_begin
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0082
    ; Restore the slow default before asserting — a failing path exits immediately.
    sep #$20
    .a8
    stz $420D
    rep #$20
    .a16
    lda f:$7E0080
    sec
    sbc f:$7E0082     ; slow - fast, so a working FastROM is positive
    cmp #$000E
    bcs :+
    jmp @fail1
  :
    cmp #$0013
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; MEMSEL did not change bank $80 access speed by 2 master clocks per access
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B1.02 — JOYSER is 12 clocks
; provenance: Documented (SNESdev Wiki, Memory map / timing; fullsnes)
.proc test_b1_02
    .a16
    .i16
    ; $4016 (JOYSER0, 12 clocks) against $4212 (HVBJOY, 6 clocks). $4212 is chosen as the
    ; baseline because it is the one CPU MMIO read with no side effect at all: $4210 and $4211
    ; are read-to-clear, and clearing a pending flag mid-measurement would change the test.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    jsr hv_begin
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    lda $4212
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$20
    .a8
    jsr hv_begin
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    lda $4016
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080     ; joypad - mmio
    cmp #$0016
    bcs :+
    jmp @fail1
  :
    cmp #$001B
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the joypad ports were not 6 master clocks slower per access than CPU MMIO
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B2.04 — NTSC frame is 262 lines
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b2_04
    .a16
    .i16
    ; Start at vblank, poll V until it wraps to the top of the next frame, keep the maximum.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $2133         ; SETINI: no interlace (see B2.05 — test order must not decide this)
    jsr wait_vblank
    jsr wait_vblank   ; V is now at the first vblank line of a settled frame
    rep #$30
    .a16
    .i16
    lda #$0000
    sta f:$7E0120     ; running maximum
@vloop:
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    cmp f:$7E0120
    bcc :+
    sta f:$7E0120
    :
    cmp #100          ; below 100 means the counter has wrapped into the next frame
    bcs @vloop
    lda f:$7E0120
    cmp #311
    bne :+
    ; SKIP: V topped out at 311 — this is a PAL machine, so B2.05 is the applicable assertion
    sep #$20
    .a8
    lda #VERDICT_SKIP
    sta f:V_TEST_RESULT
    jml test_restore
    ; unreachable — restores the assembler's width belief only
    .a16
    .i16
    :
    cmp #$0105
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the V counter did not reach 261 (an NTSC frame is 262 lines, 0-261)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B4.03 — RDNMI sets at vblank
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b4_03
    .a16
    .i16
    ; The runtime keeps NMI disabled and polls, so this samples the flag with $4200.7 clear.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda $4210         ; clear any flag left pending by an earlier test
    jsr wait_vblank   ; land on a vblank boundary
    jsr wait_vblank   ; and again, so the flag was set by THIS vblank
    lda $4210
    and #$80
    cmp #$80
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; RDNMI bit 7 was not set at vblank while NMI was disabled
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B4.16 — H-IRQ position (golden)
; provenance: Contested (no source pins the fired dot at single-dot precision; recorded as the before/after guard for T-06-A's clock-domain comparator change)
.proc test_b4_16
    .a16
    .i16
    bra @body
@handler:
    rep #$30
    .a16
    .i16
    pha
    sep #$20
    .a8
    lda $2137         ; latch H and V at handler entry
    lda $213C
    xba
    lda $213C
    and #$01
    xba
    rep #$20
    .a16
    and #$01FF
    sta f:$7E0136
    sep #$20
    .a8
    lda $4211         ; acknowledge
    lda #$01
    sta f:$7E0134     ; tell the spin loop to stop
    rep #$30
    .a16
    .i16
    pla
    rti
@body:
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    rep #$20
    .a16
    lda #@handler
    sta a:V_IRQ_VEC
    sep #$20
    .a8
    ; --- below the long dots: HTIME = 100 ---
    sep #$20
    .a8
    lda #$00
    sta f:$7E0134     ; rendezvous byte: the handler sets it (STZ has no long form)
    lda #$64
    sta $4207
    lda #$00
    sta $4208         ; HTIME = 100
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ enabled, NMI off, auto-joypad off
    cli
@spin1:
    nop
    nop
    nop
    nop
    lda f:$7E0134
    beq @spin1
    sei
    rep #$20
    .a16
    lda f:$7E0136
    ; record slot 126: B4.16 H latched, HTIME=100 (below dots 323/327)
    sta f:$7EE2FC
    sep #$20
    .a8
    ; --- above both long dots: HTIME = 330 ---
    sep #$20
    .a8
    lda #$00
    sta f:$7E0134     ; rendezvous byte: the handler sets it (STZ has no long form)
    lda #$4A
    sta $4207
    lda #$01
    sta $4208         ; HTIME = 330
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ enabled, NMI off, auto-joypad off
    cli
@spin2:
    nop
    nop
    nop
    nop
    lda f:$7E0134
    beq @spin2
    sei
    rep #$20
    .a16
    lda f:$7E0136
    ; record slot 127: B4.16 H latched, HTIME=330 (above dots 323/327)
    sta f:$7EE2FE
    ; Disarm before reporting.
    sep #$20
    .a8
    stz $4200
    lda $4211
    ; Variant 1 = both readings arrived. The numbers are the point and live in the channel;
    ; the verdict only announces a core whose H-IRQ stopped firing at one of the two.
    lda #$03
    sta f:$7EE010
    jml test_restore
.endproc

; B4.17 — NMI enable is a level
; provenance: Documented (SNESdev Wiki NMITIMEN/RDNMI [ERRATA]; fullsnes $4200/$4210)
.proc test_b4_17
    .a16
    .i16
    bra @body
@handler:
    rep #$30
    .a16
    .i16
    pha
    sep #$20
    .a8
    .a8
    lda #$01
    sta f:$7E01C0     ; the handler ran
    lda f:$004210     ; acknowledge; long, so DBR cannot matter
    rep #$30
    .a16
    .i16
    .a16
    .i16
    pla
    rti
@body:
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $4200         ; NMI off while this is set up
    lda $4210         ; clear any latch left by an earlier test
    rep #$20
    .a16
    lda #@handler
    sta a:V_NMI_VEC
    sep #$20
    .a8
    lda #$00
    sta f:$7E01C0
    ; Enter vblank and leave the RDNMI latch ALONE -- reading $4210 here would clear the very
    ; condition under test.
    jsr wait_vblank
    ; The vblank edge is now behind us. A core that fires only on that edge has missed it.
    lda #$80
    sta $4200         ; enable NMI with the latch already up
    ; A few instructions for the interrupt to be taken; it should already have happened.
    nop
    nop
    nop
    nop
    stz $4200         ; disarm before asserting; a failure exits immediately
    lda $4210         ; leave the latch clean for whatever runs next
    lda f:$7E01C0
    cmp #$01
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; enabling NMI with RDNMI already latched did not fire an NMI — the core is treating the enable as an edge rather than a level
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B4.04 — RDNMI is read-to-clear
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b4_04
    .a16
    .i16
    ; Read twice back to back inside one vblank. The first read must report and consume the
    ; flag; the second must find it gone.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda $4210
    jsr wait_vblank
    jsr wait_vblank
    lda $4210
    and #$80
    cmp #$80
    beq :+
    jmp @fail1
  :
    lda $4210         ; the same vblank, immediately after
    and #$80
    cmp #$00
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; RDNMI bit 7 was not set on the first read of a vblank
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; RDNMI did not clear on read
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; B4.05 — RDNMI auto-clears
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b4_05
    .a16
    .i16
    ; Reach vblank and deliberately do NOT read $4210, then wait for active display and read.
    ; The flag must already be gone.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda $4210         ; clear anything left pending by an earlier test
    jsr wait_vblank
    jsr wait_vblank   ; in vblank, flag set, and left unread
@wa:
    lda $4212
    and #$80
    bne @wa           ; wait for vblank to end
    lda $4210
    and #$80
    cmp #$00
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; RDNMI stayed set past the end of vblank (it must auto-clear, not only clear on read)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B4.08 — V-IRQ fires at VTIME
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b4_08
    .a16
    .i16
    ; VTIME = 100, V-IRQ only. I is set so nothing vectors; $4211 is polled instead. The V
    ; counter is latched the moment the flag appears and must still be on the programmed line.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei               ; observe the comparator, do not dispatch
    lda #100
    sta $4209
    stz $420A         ; VTIME = 100
    lda $4211         ; clear any stale latch
    lda #$20
    sta $4200         ; V-IRQ enabled, NMI off, auto-joypad off
@wirq:
    lda $4211
    and #$80
    beq @wirq
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    sta f:$7E0122
    ; Disarm before asserting — a failing path exits straight to test_restore.
    sep #$20
    .a8
    stz $4200
    lda $4211
    rep #$20
    .a16
    lda f:$7E0122
    cmp #$0064
    bcs :+
    jmp @fail1
  :
    cmp #$0067
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the V-IRQ did not fire on the programmed scanline
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B4.12 — $4211 read releases IRQ
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b4_12
    .a16
    .i16
    ; Wait for the IRQ, acknowledging it with the same read that detects it. Then disarm, so
    ; nothing can re-assert what the read released, and look again.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    lda #100
    sta $4209
    stz $420A
    lda $4211
    lda #$20
    sta $4200
@wirq2:
    lda $4211
    and #$80
    beq @wirq2        ; this read both detects and acknowledges
    ; Disarm BEFORE looking again. The claim is that a read releases the latch; while the
    ; comparator still matches -- a V-only IRQ matches for the whole scanline -- a core is free
    ; to re-assert it, and a second read on the same line then says nothing about the release.
    ; Asserting the stronger thing made this test depend on where in the scanline the polling
    ; loop happened to catch the flag: it began failing on Mesen2 when an unrelated change
    ; moved the battery's code by a few bytes.
    stz $4200         ; disarm, so nothing can re-assert what the read released
    lda $4211         ; must now read clear
    sta f:$7E0124
    lda f:$7E0124
    and #$80
    cmp #$00
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; $4211 did not release the IRQ latch on read
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B4.15 — CPU revision (golden)
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b4_15
    .a16
    .i16
    ; Report the low nibble of $4210 as the variant code.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda $4210
    and #$0F          ; CPU revision
    asl a
    ora #$01          ; encode as (revision << 1) | 1
    sta f:$7EE010
    jml test_restore
.endproc

; B5.01 — 8x8 unsigned multiply
; provenance: Documented (SNESdev Wiki, CPU registers; fullsnes)
.proc test_b5_01
    .a16
    .i16
    ; $5A * $03 = $010E, chosen so the answer straddles both result bytes and neither can be
    ; right by accident if the halves are swapped.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$5A
    sta $4202
    lda #$03
    sta $4203         ; the write to $4203 starts the multiply
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    rep #$20
    .a16
    lda $4216
    cmp #$010E
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; 8x8 multiply produced the wrong product
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B5.02 — 16/8 unsigned divide
; provenance: Documented (SNESdev Wiki, CPU registers; fullsnes)
.proc test_b5_02
    .a16
    .i16
    ; $04D2 / $07 = $B0 remainder $02 (1234 / 7 = 176 r2). The divide needs 16 CPU cycles.
    rep #$30
    .a16
    .i16
    phk
    plb
    lda #$04D2
    sta $4204         ; 16-bit store fills $4204/$4205
    sep #$20
    .a8
    lda #$07
    sta $4206         ; the write to $4206 starts the divide
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    rep #$20
    .a16
    lda $4214
    cmp #$00B0
    beq :+
    jmp @fail1
  :
    lda $4216
    cmp #$0002
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; 16/8 divide produced the wrong quotient
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; 16/8 divide produced the wrong remainder
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; B5.03 — Divide by zero
; provenance: Documented (SNESdev Wiki, CPU registers; fullsnes)
.proc test_b5_03
    .a16
    .i16
    ; $1234 / 0 -> quotient $FFFF, remainder $1234.
    rep #$30
    .a16
    .i16
    phk
    plb
    lda #$1234
    sta $4204
    sep #$20
    .a8
    stz $4206         ; divide by zero
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    rep #$20
    .a16
    lda $4214
    cmp #$FFFF
    beq :+
    jmp @fail1
  :
    lda $4216
    cmp #$1234
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; divide by zero did not saturate the quotient to $FFFF
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; divide by zero did not leave the dividend as the remainder
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; B5.04 — Mul/div overlap (golden)
; provenance: Contested (SNESdev Errata states overlapping $4203/$4206 operation is undefined)
.proc test_b5_04
    .a16
    .i16
    ; Start a divide, then start a multiply before it can finish, and report what RDMPY holds.
    rep #$30
    .a16
    .i16
    phk
    plb
    lda #$1234
    sta $4204
    sep #$20
    .a8
    lda #$07
    sta $4206         ; divide begins
    lda #$5A
    sta $4202
    lda #$03
    sta $4203         ; multiply begins while the divide is still in flight
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    lda $4216         ; whatever the shared register ended up holding
    and #$0F          ; low nibble only — the full byte does not fit a variant code
    asl a
    ora #$01
    sta f:$7EE010
    jml test_restore
.endproc

; B5.05 — Mul/div power-on state
; provenance: Documented (anomie regs.txt r1157 and nocash fullsnes, independently; implemented by bsnes/ares/Mesen2. No known hardware test ROM)
.proc test_b5_05
    .a16
    .i16
    ; $FF x 2 = $01FE, and $FFFF / 2 = $7FFF remainder 1, read from the pre-init capture block.
    rep #$30
    .a16
    .i16
    phk
    plb
    lda f:$7EE040     ; V_PO_MPY
    cmp #$01FE
    beq :+
    jmp @fail1
  :
    lda f:$7EE042     ; V_PO_DIV
    cmp #$7FFF
    beq :+
    jmp @fail2
  :
    lda f:$7EE044     ; V_PO_DIVREM
    cmp #$0001
    beq :+
    jmp @fail3
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; $4202 did not power up as $FF (the captured product was not $FF x 2)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; $4204/05 did not power up as $FFFF (the captured quotient was not $FFFF / 2)
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; the captured power-on divide remainder was wrong
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
.endproc

; B1.03 — Internal cycles are 6
; provenance: Documented (SNES Development Manual Bk I 21.1; SNESdev Wiki; fullsnes)
.proc test_b1_03
    .a16
    .i16
    ; XBA minus NOP is exactly one internal cycle: 6 clocks, so 24 dots over 16 repeats.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$30
    .a8
    .i8
    jsr hv_begin
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0098
    ; record slot 70: 16 NOP, absolute
    sta f:$7EE28C
    sep #$30
    .a8
    .i8
    jsr hv_begin
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0098
    ; record slot 71: 16 XBA - 16 NOP = 16 internal cycles
    sta f:$7EE28E
    cmp #$0016
    bcs :+
    jmp @fail1
  :
    cmp #$001B
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; one internal cycle did not cost 6 master clocks
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B1.04 — DMA speed is uniform
; provenance: Documented (SNES Development Manual Bk I 21.1 (DMA at 2.68MHz regardless of address))
.proc test_b1_04
    .a16
    .i16
    ; 32 bytes to the VRAM port, once from a MEMSEL-fast bank and once from a slow one.
    ; Forced blank is in force for the whole battery, so VRAM is writable throughout.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$01
    sta $420D         ; MEMSEL = 1: banks $80+ are a 6-clock region for the CPU
    lda #$80
    sta $2115         ; VMAIN step 1, increment after the high byte
    ; --- channel 0: A->B, mode 1 (two registers), destination $2118 ---
    lda #$01
    sta $4300
    lda #$18
    sta $4301
    ; --- transfer 1: source $80:8000, the CPU-fast bank ---
    rep #$30
    .a16
    .i16
    ldx #$1800
    stx $2116
    ldx #$8000
    stx $4302
    sep #$20
    .a8
    lda #$80
    sta $4304
    rep #$30
    .a16
    .i16
    ldx #$0020
    stx $4305         ; 32 bytes
    sep #$20
    .a8
    jsr hv_begin
    lda #$01
    sta $420B         ; start channel 0
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E009A
    ; record slot 72: DMA 32B from a MEMSEL-fast bank
    sta f:$7EE290
    ; --- transfer 2: identical, but sourced from bank $00 (always 8 clocks for the CPU) ---
    rep #$30
    .a16
    .i16
    ldx #$1900
    stx $2116
    ldx #$8000
    stx $4302
    sep #$20
    .a8
    stz $4304         ; bank $00
    rep #$30
    .a16
    .i16
    ldx #$0020
    stx $4305
    sep #$20
    .a8
    jsr hv_begin
    lda #$01
    sta $420B
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 73: DMA 32B from a slow bank
    sta f:$7EE292
    ; --- restore MEMSEL before asserting; a failing path exits immediately ---
    sep #$20
    .a8
    stz $420D
    rep #$20
    .a16
    sec
    sbc f:$7E009A
    cmp #$8000
    bcc :+
    eor #$FFFF
    inc a             ; negate: take the magnitude
  :
    cmp #$0003
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; DMA timing changed with the source region — it must be 8 clocks/byte regardless
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B2.06 — Interlace line count
; provenance: Contested (the dossier conditions the extra line on $213F.7 (the field), which this test does not control — sampling V across an uncontrolled field cannot assert a line count)
.proc test_b2_06
    .a16
    .i16
    ; Enable interlace, let a full frame pass so the setting is stable, then find V's maximum.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$01
    sta $2133         ; SETINI bit 0 = screen interlace
    jsr wait_vblank
    jsr wait_vblank   ; a settled frame under the new setting
    rep #$30
    .a16
    .i16
    lda #$0000
    sta f:$7E0126
@iloop:
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    cmp f:$7E0126
    bcc :+
    sta f:$7E0126
    :
    cmp #100
    bcs @iloop
    sep #$20
    .a8
    stz $2133         ; restore before asserting
    rep #$20
    .a16
    lda f:$7E0126
    ; record slot 74: V counter maximum with interlace enabled
    sta f:$7EE294
    ; Report which line count was seen: variant 1 = 261 (no extra line), 2 = 262, 3 = other.
    ; Both comparisons run while A is still 16-bit and the answer is staged in X; narrowing on
    ; one branch would leave the generator's width tracker wrong for the other path's `cmp`.
    ldx #$0007        ; default: variant 3 = something else
    cmp #261
    bne :+
    ldx #$0003        ; variant 1 = 261, no extra line
    :
    cmp #262
    bne :+
    ldx #$0005        ; variant 2 = 262, interlace added a line
    :
    sep #$20
    .a8
    txa
    sta f:$7EE010
    jml test_restore
.endproc

; B2.05 — PAL frame is 312 lines
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b2_05
    .a16
    .i16
    ; Identical to B2.04's measurement; only the expected line count differs.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $2133         ; SETINI: no interlace — B2.06 leaves it ON, and an interlaced PAL
    ; frame is 313 lines on the long field, so measuring frame height without clearing this
    ; measures B2.06's leftovers instead. Found by the PAL image: B2.04 skipped (it saw 311)
    ; while B2.05 failed, which is only possible if the two measured different machines.
    jsr wait_vblank
    jsr wait_vblank   ; a settled frame under the cleared setting
    rep #$30
    .a16
    .i16
    lda #$0000
    sta f:$7E0120     ; running maximum
@vloop:
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    cmp f:$7E0120
    bcc :+
    sta f:$7E0120
    :
    cmp #100          ; below 100 means the counter has wrapped into the next frame
    bcs @vloop
    lda f:$7E0120
    cmp #261
    bne :+
    ; SKIP: V topped out at 261 — this is an NTSC machine, so B2.04 is the applicable assertion
    sep #$20
    .a8
    lda #VERDICT_SKIP
    sta f:V_TEST_RESULT
    jml test_restore
    ; unreachable — restores the assembler's width belief only
    .a16
    .i16
    :
    cmp #$0137
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the V counter did not reach 311 (a PAL frame is 312 lines, 0-311)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B4.14 — IRQ dispatch latency
; provenance: Documented (SNESdev Wiki, Timing; fullsnes — the sub-cycle poll point is not CPU-observable, so its consequence is measured instead)
.proc test_b4_14
    .a16
    .i16
    ; Arm an H-IRQ at a known dot, install a handler that latches H on entry, and spin. The
    ; latched dot minus HTIME is the dispatch latency. Run it twice with different spin bodies.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    ; Install the handler. It latches H, acknowledges, flags the spin loop, and returns.
    rep #$20
    .a16
    lda #@handler
    sta a:V_IRQ_VEC
    sep #$20
    .a8
    ; Pass 1: spin on NOPs, the shortest instruction there is.
    sep #$20
    .a8
    lda #$00
    sta f:$7E0134     ; rendezvous byte: the handler sets it (STZ has no long form)
    lda #$C8
    sta $4207
    lda #$00
    sta $4208         ; HTIME = 200
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ enabled, NMI off, auto-joypad off
    cli
@spin1:
    nop
    nop
    nop
    nop
    lda f:$7E0134
    beq @spin1
    sei
    rep #$20
    .a16
    lda f:$7E0136     ; H latched on handler entry
    sec
    sbc #200          ; minus HTIME: the dispatch latency in dots
    ; record slot 100: B4.14 dispatch latency, NOP spin (dots)
    sta f:$7EE2C8
    sta f:$7E0138
    sep #$20
    .a8
    ; Pass 2: spin on JSL/RTL. If the poll were continuous rather than at an instruction
    ; boundary, this would enter the handler in the same place as pass 1.
    sep #$20
    .a8
    lda #$00
    sta f:$7E0134     ; rendezvous byte: the handler sets it (STZ has no long form)
    lda #$C8
    sta $4207
    lda #$00
    sta $4208         ; HTIME = 200
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ enabled, NMI off, auto-joypad off
    cli
@spin2:
    jsl @far
    sep #$20
    .a8
    lda f:$7E0134
    beq @spin2
    sei
    rep #$20
    .a16
    lda f:$7E0136
    sec
    sbc #200
    ; record slot 101: B4.14 dispatch latency, JSL/RTL spin (dots)
    sta f:$7EE2CA
    sec
    sbc f:$7E0138     ; the extra delay a long instruction imposes
    ; record slot 102: B4.14 extra latency from the long spin body (dots)
    sta f:$7EE2CC
    ; Restore the default handler before leaving — the vector is global state.
    sep #$20
    .a8
    stz $4200
    lda $4211
    rep #$20
    .a16
    lda #irq_stub
    sta a:V_IRQ_VEC
    sep #$20
    .a8
    lda #$01
    sta f:V_TEST_RESULT   ; golden: the numbers live in the measurement channel
    jml test_restore
    ; --- the far routine the long spin calls ---
@far:
    rtl
    ; --- the handler ---
@handler:
    rep #$30
    .a16
    .i16
    pha
    sep #$20
    .a8
    lda $2137         ; latch H and V at handler entry
    lda $213C
    xba
    lda $213C
    and #$01
    xba
    rep #$20
    .a16
    and #$01FF
    sta f:$7E0136
    sep #$20
    .a8
    lda $4211         ; acknowledge
    lda #$01
    sta f:$7E0134     ; tell the spin loop to stop
    rep #$20
    .a16
    pla
    rti
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
.endproc

; B2.10 — Region bit (golden)
; provenance: Contested (SNESdev PPU registers places the 50/60Hz bit at bit 3, which overlaps the PPU2 version field; fullsnes places it at bit 4)
.proc test_b2_10
    .a16
    .i16
    ; Report $213F bits 4 and 3 together so the encoding conflict is visible in the result.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda $213F
    sta f:$7E0128
    and #$10          ; candidate region bit per fullsnes
    lsr a
    lsr a
    lsr a           ; -> bit 1
    sta f:$7E0129
    lda f:$7E0128
    and #$08          ; candidate region bit per SNESdev PPU registers
    lsr a
    lsr a
    lsr a           ; -> bit 0
    ora f:$7E0129
    asl a
    ora #$01
    sta f:$7EE010
    jml test_restore
.endproc

; B4.07 — H-IRQ position (golden)
; provenance: Contested (the $4211 poll loop is coarser than the dot the comparator fires on, so the exact H position is not resolvable from software by polling)
.proc test_b4_07
    .a16
    .i16
    ; HTIME = 128, H-IRQ only. Poll $4211, then latch H and check it is on the programmed dot.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    lda #$80
    sta $4207
    stz $4208         ; HTIME = 128
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ enabled, NMI off, auto-joypad off
@wh:
    lda $4211
    and #$80
    beq @wh
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213C
    xba
    lda $213C
    and #$01
    xba
    rep #$20
    .a16
    and #$01FF
    sta f:$7E012A
    ; record slot 75: H position when the H-IRQ was observed
    sta f:$7EE296
    ; --- disarm before asserting ---
    sep #$20
    .a8
    stz $4200
    lda $4211
    rep #$20
    .a16
    lda f:$7E012A
    ; Report the latched H in 32-dot buckets. The poll loop is coarser than the dot the IRQ
    ; actually fires on, so the exact position is not resolvable from software this way.
    lsr a
    lsr a
    lsr a
    lsr a
    lsr a           ; H / 32
    sep #$20
    .a8
    asl a
    ora #$01
    sta f:$7EE010
    jml test_restore
.endproc

; B4.09 — HV-IRQ needs both
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_b4_09
    .a16
    .i16
    ; HTIME = 128, VTIME = 150, both enabled. The IRQ must appear on line 150 specifically.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    lda #$80
    sta $4207
    stz $4208         ; HTIME = 128
    lda #150
    sta $4209
    stz $420A         ; VTIME = 150
    lda $4211
    lda #$30
    sta $4200         ; both H-IRQ and V-IRQ enabled
@whv:
    lda $4211
    and #$80
    beq @whv
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    sta f:$7E012C
    ; record slot 76: V position when the HV-IRQ was observed
    sta f:$7EE298
    sep #$20
    .a8
    stz $4200
    lda $4211
    rep #$20
    .a16
    lda f:$7E012C
    cmp #$0096
    bcs :+
    jmp @fail1
  :
    cmp #$0099
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the HV-IRQ did not require both comparators to match
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; B3.01 — DRAM refresh pause
; provenance: Contested (fullsnes and anomie put the pause at 40 clocks near line-clock 536, but ares' own source calls its refresh pattern technically wrong and only right on average, and docs/accuracy-ledger.md scopes refresh out of RustySNES on the measurement that its frame length is already correct without one)
.proc test_b3_01
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    stz $4200         ; no NMI and no timer IRQs
    stz $420C         ; no HDMA -- the only other thing that steals CPU cycles per line
    ; Settle on a frame boundary, then walk forward until H is near the start of a line, so
    ; the window that follows has a whole scanline in front of it.
    jsr wait_vblank
    sep #$20
    .a8
    rep #$10
    .i16
@sync:
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213C         ; H low
    sta f:$7E0160
    lda $213C         ; H high
    and #$01
    bne @sync         ; H >= 256: no room left in this line
    lda f:$7E0160
    cmp #16
    bcs @sync
    ; Four samples of the full 9-bit counter, into $7E0160..$7E0167 as 16-bit words.
    ldx #$0000
@sloop:
    lda $2137         ; latch
    lda $213C         ; H low
    sta f:$7E0160,x
    lda $213C         ; H high
    and #$01          ; bits 1-7 are PPU2 open bus
    sta f:$7E0161,x
    inx
    inx
    cpx #$0008
    bne @sloop
    ; Difference the samples.
    rep #$30
    .a16
    .i16
    lda #$FFFF
    sta f:$7E0168     ; running minimum
    lda #$0000
    sta f:$7E016A     ; running maximum
    sta f:$7E016C     ; H at the start of the longest interval
    ldx #$0000
@dloop:
    lda f:$7E0162,x
    sec
    sbc f:$7E0160,x
    cmp f:$7E0168
    bcs :+
    sta f:$7E0168
    :
    cmp f:$7E016A
    bcc :+
    beq :+
    sta f:$7E016A
    lda f:$7E0160,x   ; the sample the longest interval starts from
    sta f:$7E016C
    :
    inx
    inx
    cpx #$0006
    bne @dloop
    ; The window bounds are recorded too: without them a reader cannot tell whether the pause
    ; was inside the sampled span or never had a chance to appear.
    lda f:$7E0168
    ; record slot 106: B3 shortest interval in dots (the stall-free loop period)
    sta f:$7EE2D4
    lda f:$7E016A
    ; record slot 107: B3 longest interval in dots
    sta f:$7EE2D6
    lda f:$7E016C
    ; record slot 108: B3 H at the start of the longest interval
    sta f:$7EE2D8
    lda f:$7E0160
    ; record slot 109: B3 H at the first sample (window start)
    sta f:$7EE2DA
    lda f:$7E0166
    ; record slot 124: B3 H at the last sample (window end)
    sta f:$7EE2F8
    lda f:$7E016A
    cmp #200
    bcc :+
    ; No loop iteration takes 200 dots. A delta that large means the window crossed a line
    ; boundary and the samples ran backwards -- say so rather than report a giant pause.
    sep #$20
    .a8
    lda #$07          ; variant 3 = window left the scanline, measurement invalid
    sta f:$7EE010
    jml test_restore
    :
    rep #$30
    .a16
    .i16
    lda f:$7E016A
    sec
    sbc f:$7E0168
    cmp #4
    bcs :+
    sep #$20
    .a8
    lda #$03          ; variant 1 = the intervals are flat; no per-line pause is modelled
    sta f:$7EE010
    jml test_restore
    :
    sep #$20
    .a8
    lda #$05          ; variant 2 = one interval stands out; slots 106/107 size it
    sta f:$7EE010
    jml test_restore
.endproc

; B4.13 — Timer range is 9-bit
; provenance: Documented (fullsnes $4207-$420A: HTIME is 0-339 and VTIME 0-261 (NTSC) / 0-311 (PAL), both held in nine bits)
.proc test_b4_13
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    stz $4200
    lda $4211         ; clear any latch an earlier test left
    ; --- control: HTIME = 100 is squarely in range and must fire ---
    sep #$20
    .a8
    lda #$64
    sta $4207
    lda #$00
    sta $4208         ; HTIME = 100
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ only
    ; Bounded wait: poll $4211 while counting vblank edges.
    sep #$30
    .a8
    .i8
    lda #$00
    sta f:$7E0170     ; the fired flag (STZ has no long form)
    ldx #2
@outa:
@acta:
    lda $4211
    and #$80
    bne @hita
    lda $4212
    and #$80
    bne @acta     ; still in vblank; wait for active display
@vbla:
    lda $4211
    and #$80
    bne @hita
    lda $4212
    and #$80
    beq @vbla     ; wait for the next vblank edge
    dex
    bne @outa
    bra @donea
@hita:
    lda #$01
    sta f:$7E0170
@donea:
    sep #$20
    .a8
    lda f:$7E0170
    cmp #$01
    beq :+
    jmp @fail1
  :
    ; --- HTIME = 400 is past the end of every scanline and must never match ---
    sep #$20
    .a8
    lda #$90
    sta $4207
    lda #$01
    sta $4208         ; HTIME = 400
    lda $4211         ; clear any stale latch
    lda #$10
    sta $4200         ; H-IRQ only
    ; Bounded wait: poll $4211 while counting vblank edges.
    sep #$30
    .a8
    .i8
    lda #$00
    sta f:$7E0170     ; the fired flag (STZ has no long form)
    ldx #3
@outb:
@actb:
    lda $4211
    and #$80
    bne @hitb
    lda $4212
    and #$80
    bne @actb     ; still in vblank; wait for active display
@vblb:
    lda $4211
    and #$80
    bne @hitb
    lda $4212
    and #$80
    beq @vblb     ; wait for the next vblank edge
    dex
    bne @outb
    bra @doneb
@hitb:
    lda #$01
    sta f:$7E0170
@doneb:
    sep #$20
    .a8
    lda f:$7E0170
    cmp #$00
    beq :+
    jmp @fail2
  :
    ; --- control: VTIME = 100 is in range on both NTSC and PAL and must fire ---
    sep #$20
    .a8
    lda #$64
    sta $4209
    lda #$00
    sta $420A         ; VTIME = 100
    lda $4211         ; clear any stale latch
    lda #$20
    sta $4200         ; V-IRQ only
    ; Bounded wait: poll $4211 while counting vblank edges.
    sep #$30
    .a8
    .i8
    lda #$00
    sta f:$7E0170     ; the fired flag (STZ has no long form)
    ldx #2
@outc:
@actc:
    lda $4211
    and #$80
    bne @hitc
    lda $4212
    and #$80
    bne @actc     ; still in vblank; wait for active display
@vblc:
    lda $4211
    and #$80
    bne @hitc
    lda $4212
    and #$80
    beq @vblc     ; wait for the next vblank edge
    dex
    bne @outc
    bra @donec
@hitc:
    lda #$01
    sta f:$7E0170
@donec:
    sep #$20
    .a8
    lda f:$7E0170
    cmp #$01
    beq :+
    jmp @fail3
  :
    ; --- VTIME = 400 is past the last line of either region and must never match ---
    ; 400 rather than 300: 300 is out of range on NTSC but a real line on PAL, and the battery
    ; ships both images. 400 is beyond 261 and 311 alike, so one assertion covers both.
    sep #$20
    .a8
    lda #$90
    sta $4209
    lda #$01
    sta $420A         ; VTIME = 400
    lda $4211         ; clear any stale latch
    lda #$20
    sta $4200         ; V-IRQ only
    ; Bounded wait: poll $4211 while counting vblank edges.
    sep #$30
    .a8
    .i8
    lda #$00
    sta f:$7E0170     ; the fired flag (STZ has no long form)
    ldx #3
@outd:
@actd:
    lda $4211
    and #$80
    bne @hitd
    lda $4212
    and #$80
    bne @actd     ; still in vblank; wait for active display
@vbld:
    lda $4211
    and #$80
    bne @hitd
    lda $4212
    and #$80
    beq @vbld     ; wait for the next vblank edge
    dex
    bne @outd
    bra @doned
@hitd:
    lda #$01
    sta f:$7E0170
@doned:
    sep #$20
    .a8
    lda f:$7E0170
    cmp #$00
    beq :+
    jmp @fail4
  :
    sep #$20
    .a8
    stz $4200
    lda $4211
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; no H-IRQ arrived with HTIME = 100, which is in range — so the out-of-range check that follows would report silence for the wrong reason
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; an H-IRQ fired with HTIME = 400, which no scanline reaches: a core keeping only the low eight bits arms at 144, one reducing modulo the line length arms at 59
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; no V-IRQ arrived with VTIME = 100, which is in range on both regions — the out-of-range check that follows would report silence for the wrong reason
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
@fail4:
    ; a V-IRQ fired with VTIME = 400, which is past the last line of either region: a core keeping only the low eight bits arms at 144
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jml test_restore
.endproc

; B4.11 — Dot 153, last line
; provenance: Contested (superfamicom.org's timing page states the exception and gives no mechanism; its timing text derives from fullsnes, so the two are one source, and no test ROM verifies it. ares, bsnes, Mesen2 and snes9x were each searched and none implements it)
.proc test_b4_11
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sei
    stz $4200
    lda $4211
    ; Measure the last line rather than assuming it: 261 on NTSC, 311 on PAL, and the region
    ; bit is too contested (B2.10) to branch on.
    sep #$20
    .a8
    stz $2133         ; SETINI: no interlace, which would add a line
    jsr wait_vblank
    jsr wait_vblank   ; a settled frame
    rep #$30
    .a16
    .i16
    lda #$0000
    sta f:$7E0124     ; running maximum
@fh_loop:
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    cmp f:$7E0124
    bcc :+
    sta f:$7E0124
    :
    cmp #100          ; below 100 means the counter wrapped into the next frame
    bcs @fh_loop
    lda f:$7E0124
    sta f:$7E0172     ; the last line of a frame
    dec a
    sta f:$7E0174     ; and the one before it, for the control
    ; --- the assertion: dot 153 on the last scanline ---
    sep #$20
    .a8
    lda #$99
    sta $4207
    lda #$00
    sta $4208         ; HTIME = 153
    lda f:$7E0172
    sta $4209
    lda f:$7E0173
    and #$01
    sta $420A         ; VTIME from the measured line
    lda $4211         ; clear any stale latch
    lda #$30
    sta $4200         ; both comparators, so the match is one dot on one line
    ; Bounded wait: poll $4211 while counting vblank edges.
    sep #$30
    .a8
    .i8
    lda #$00
    sta f:$7E0170     ; the fired flag (STZ has no long form)
    ldx #3
@oute:
@acte:
    lda $4211
    and #$80
    bne @hite
    lda $4212
    and #$80
    bne @acte     ; still in vblank; wait for active display
@vble:
    lda $4211
    and #$80
    bne @hite
    lda $4212
    and #$80
    beq @vble     ; wait for the next vblank edge
    dex
    bne @oute
    bra @donee
@hite:
    lda #$01
    sta f:$7E0170
@donee:
    sep #$20
    .a8
    lda f:$7E0170
    sta f:$7E0177
    ; --- control: the same dot one line earlier must fire ---
    sep #$20
    .a8
    lda #$99
    sta $4207
    lda #$00
    sta $4208         ; HTIME = 153
    lda f:$7E0174
    sta $4209
    lda f:$7E0175
    and #$01
    sta $420A         ; VTIME from the measured line
    lda $4211         ; clear any stale latch
    lda #$30
    sta $4200         ; both comparators, so the match is one dot on one line
    ; Bounded wait: poll $4211 while counting vblank edges.
    sep #$30
    .a8
    .i8
    lda #$00
    sta f:$7E0170     ; the fired flag (STZ has no long form)
    ldx #3
@outf:
@actf:
    lda $4211
    and #$80
    bne @hitf
    lda $4212
    and #$80
    bne @actf     ; still in vblank; wait for active display
@vblf:
    lda $4211
    and #$80
    bne @hitf
    lda $4212
    and #$80
    beq @vblf     ; wait for the next vblank edge
    dex
    bne @outf
    bra @donef
@hitf:
    lda #$01
    sta f:$7E0170
@donef:
    sep #$20
    .a8
    lda f:$7E0170
    sta f:$7E0178
    ; --- control: a different dot on the same last line must fire ---
    sep #$20
    .a8
    lda #$64
    sta $4207
    lda #$00
    sta $4208         ; HTIME = 100
    lda f:$7E0172
    sta $4209
    lda f:$7E0173
    and #$01
    sta $420A         ; VTIME from the measured line
    lda $4211         ; clear any stale latch
    lda #$30
    sta $4200         ; both comparators, so the match is one dot on one line
    ; Bounded wait: poll $4211 while counting vblank edges.
    sep #$30
    .a8
    .i8
    lda #$00
    sta f:$7E0170     ; the fired flag (STZ has no long form)
    ldx #3
@outg:
@actg:
    lda $4211
    and #$80
    bne @hitg
    lda $4212
    and #$80
    bne @actg     ; still in vblank; wait for active display
@vblg:
    lda $4211
    and #$80
    bne @hitg
    lda $4212
    and #$80
    beq @vblg     ; wait for the next vblank edge
    dex
    bne @outg
    bra @doneg
@hitg:
    lda #$01
    sta f:$7E0170
@doneg:
    sep #$20
    .a8
    lda f:$7E0170
    sta f:$7E0179
    sep #$20
    .a8
    stz $4200
    lda $4211
    ; Publish all three readings: the verdict compresses them, the channel keeps them.
    rep #$30
    .a16
    .i16
    lda f:$7E0172
    ; record slot 77: B4.11 the measured last line of a frame
    sta f:$7EE29A
    lda f:$7E0177
    and #$00FF
    ; record slot 78: B4.11 fired at dot 153 on the last line (0 = suppressed)
    sta f:$7EE29C
    lda f:$7E0178
    and #$00FF
    ; record slot 79: B4.11 control: fired at dot 153 one line earlier
    sta f:$7EE29E
    lda f:$7E0179
    and #$00FF
    ; record slot 80: B4.11 control: fired at dot 100 on the last line
    sta f:$7EE2A0
    ; Either control staying silent means the HV-IRQ path never worked here, and the reading
    ; above is not evidence of a suppression.
    sep #$30
    .a8
    .i8
    lda f:$7E0178
    beq :+
    lda f:$7E0179
    beq :+
    lda f:$7E0177
    beq :++
    lda #$03          ; variant 1 = it fired; the exception is not modelled here
    sta f:$7EE010
    jml test_restore
    :
    lda #$07          ; variant 3 = a control did not fire; inconclusive
    sta f:$7EE010
    jml test_restore
    :
    lda #$05          ; variant 2 = suppressed at dot 153 while both controls fired
    sta f:$7EE010
    jml test_restore
.endproc

; D1.01 — DMA mode 0
; provenance: Documented (SNESdev Wiki, DMA; fullsnes)
.proc test_d1_01
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22, $33, $44
@body:
    ; Mode 0 into $2180 (the WRAM data port): all four bytes land at consecutive WRAM
    ; addresses because $2180 auto-increments WMADD, not because the B-bus address moved.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$00
    sta $2181
    lda #$05
    sta $2182
    stz $2183         ; WMADD = $7E:0500, clear of every test's scratch
    stz $4300         ; DMAP: A->B, increment, mode 0
    lda #$80
    sta $4301         ; B-bus = $2180
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302         ; A-bus address = this test's data table
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; A-bus bank = this bank
    rep #$30
    .a16
    .i16
    ldx #$0004
    stx $4305         ; byte count
    sep #$20
    .a8
    lda #$01
    sta $420B         ; run channel 0
    ; Read the four bytes back and fold them into one word so a single compare covers all.
    rep #$30
    .a16
    .i16
    lda f:$7E0500
    cmp #$2211
    beq :+
    jmp @fail1
  :
    lda f:$7E0502
    cmp #$4433
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the first two bytes did not arrive in order at $7E:0500
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; the last two bytes did not arrive in order at $7E:0502
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; D1.01b — DMA mode 1
; provenance: Documented (SNESdev Wiki, DMA; fullsnes)
.proc test_d1_01b
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22, $33, $44
@body:
    ; Mode 1 into $2118/$2119: byte 0 -> VMDATAL, byte 1 -> VMDATAH, then repeat.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$80
    sta $2115         ; VMAIN: step 1 word, increment after the high byte
    rep #$30
    .a16
    .i16
    ldx #$1000
    stx $2116         ; VRAM word address $1000, clear of the font and the tilemaps
    sep #$20
    .a8
    lda #$01
    sta $4300         ; DMAP: A->B, increment, mode 1
    lda #$18
    sta $4301         ; B-bus = $2118
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302         ; A-bus address = this test's data table
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; A-bus bank = this bank
    rep #$30
    .a16
    .i16
    ldx #$0004
    stx $4305         ; byte count
    sep #$20
    .a8
    lda #$01
    sta $420B
    ; Read the two words back. Setting VMADDL primes the read latch, so the first 16-bit read
    ; of $2139/$213A already returns word $1000 — no dummy read, which would consume it.
    sep #$20
    .a8
    lda #$80
    sta $2115         ; increment after the HIGH byte, so a 16-bit read is one word
    rep #$30
    .a16
    .i16
    ldx #$1000
    stx $2116
    lda $2139
    cmp #$2211
    beq :+
    jmp @fail1
  :
    ; Re-set the address for the second word rather than relying on the read increment: the
    ; prefetch latch makes successive reads a separate question, and mixing the two would
    ; leave a failure ambiguous between the DMA and the read port.
    ldx #$1001
    stx $2116
    lda $2139
    cmp #$4433
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; VRAM word 0 is wrong: the two bytes did not split across $2118/$2119
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; VRAM word 1 is wrong
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; D1.06 — DMA count hits zero
; provenance: Documented (SNESdev Wiki, DMA registers; fullsnes)
.proc test_d1_06
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22, $33, $44
@body:
    ; Run a 4-byte transfer, then read $4305/06.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$00
    sta $2181
    lda #$06
    sta $2182
    stz $2183         ; WMADD = $7E:0600
    stz $4300
    lda #$80
    sta $4301
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302         ; A-bus address = this test's data table
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; A-bus bank = this bank
    rep #$30
    .a16
    .i16
    ldx #$0004
    stx $4305         ; byte count
    sep #$20
    .a8
    lda #$01
    sta $420B
    rep #$30
    .a16
    .i16
    lda $4305
    cmp #$0000
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the DMA byte counter did not decrement to zero
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; D1.07 — DMA fixed A-bus
; provenance: Documented (SNESdev Wiki, DMA registers; fullsnes)
.proc test_d1_07
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22, $33, $44
@body:
    ; DMAP bits 4-3 = 1: fixed source. Four bytes from one address must all be $11.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$00
    sta $2181
    lda #$07
    sta $2182
    stz $2183         ; WMADD = $7E:0700
    lda #$08
    sta $4300         ; DMAP: A->B, step field = 1 (FIXED), mode 0
    lda #$80
    sta $4301
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302         ; A-bus address = this test's data table
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; A-bus bank = this bank
    rep #$30
    .a16
    .i16
    ldx #$0004
    stx $4305         ; byte count
    sep #$20
    .a8
    lda #$01
    sta $420B
    rep #$30
    .a16
    .i16
    lda f:$7E0700
    cmp #$1111
    beq :+
    jmp @fail1
  :
    lda f:$7E0702
    cmp #$1111
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; bytes 0-1 are not both the fixed source byte
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; bytes 2-3 are not both the fixed source byte
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; D1.07b — DMA decrementing A-bus
; provenance: Documented (SNESdev Wiki, DMA registers; fullsnes)
.proc test_d1_07b
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22, $33, $44
@body:
    ; DMAP bits 4-3 = 2: decrement. Source the LAST byte; the transfer walks back.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$00
    sta $2181
    lda #$08
    sta $2182
    stz $2183         ; WMADD = $7E:0800
    lda #$10
    sta $4300         ; DMAP: A->B, step field = 2 (DECREMENT), mode 0
    lda #$80
    sta $4301
    rep #$30
    .a16
    .i16
    ldx #(@data + 3)
    stx $4302         ; start at the last byte
    sep #$20
    .a8
    phk
    pla
    sta $4304
    rep #$30
    .a16
    .i16
    ldx #$0004
    stx $4305
    sep #$20
    .a8
    lda #$01
    sta $420B
    rep #$30
    .a16
    .i16
    lda f:$7E0800
    cmp #$3344
    beq :+
    jmp @fail1
  :
    lda f:$7E0802
    cmp #$1122
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; bytes 0-1 are not the table read backwards
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; bytes 2-3 are not the table read backwards
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; D1.10 — DMA $43xB scratch latch
; provenance: Corroborated (ares and bsnes both model the latch and serialize it)
.proc test_d1_10
    .a16
    .i16
    ; Write $43xB, read it back, then read $43xF and require the same value.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$5A
    sta $430B
    lda $430B
    cmp #$5A
    beq :+
    jmp @fail1
  :
    lda $430F
    cmp #$5A
    beq :+
    jmp @fail2
  :
    ; A different channel must have its own latch, not share channel 0's.
    lda #$A5
    sta $431B
    lda $430B
    cmp #$5A
    beq :+
    jmp @fail3
  :
    lda $431F
    cmp #$A5
    beq :+
    jmp @fail4
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; $430B did not read back the value written to it
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; $430F does not mirror $430B
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; writing $431B changed channel 0's latch — the channels are not separate
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
@fail4:
    ; $431F does not mirror $431B
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jml test_restore
.endproc

; D1.02 — DMA 8 clocks/byte
; provenance: Documented (SNESdev Wiki, DMA timing; fullsnes)
.proc test_d1_02
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22, $33, $44
@body:
    ; Two mode-0 transfers into WRAM, 32 bytes apart in length. The difference is the rate.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$08
    sta $4300         ; step field = 1 (fixed): the table is only 4 bytes long
    lda #$80
    sta $4301
    ; --- 16 bytes ---
    lda #$00
    sta $2181
    lda #$09
    sta $2182
    stz $2183
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302         ; A-bus address = this test's data table
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; A-bus bank = this bank
    rep #$30
    .a16
    .i16
    ldx #$0010
    stx $4305         ; byte count
    sep #$20
    .a8
    jsr hv_begin
    lda #$01
    sta $420B
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E00A0
    ; record slot 104: D1.02 16-byte DMA (dots)
    sta f:$7EE2D0
    ; --- 48 bytes: 32 more ---
    sep #$20
    .a8
    lda #$00
    sta $2181
    lda #$0A
    sta $2182
    stz $2183
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302         ; A-bus address = this test's data table
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; A-bus bank = this bank
    rep #$30
    .a16
    .i16
    ldx #$0030
    stx $4305         ; byte count
    sep #$20
    .a8
    jsr hv_begin
    lda #$01
    sta $420B
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 105: D1.02 48-byte DMA (dots)
    sta f:$7EE2D2
    sec
    sbc f:$7E00A0
    ; record slot 106: D1.02 difference — expect 32 bytes x 8 clocks = 64 dots
    sta f:$7EE2D4
    cmp #$003C
    bcs :+
    jmp @fail1
  :
    cmp #$0045
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; 32 extra DMA bytes did not cost 64 dots (8 clocks each)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; D1.05 — DMA count 0 = 65536
; provenance: Documented (SNESdev Wiki, DMA registers; fullsnes)
.proc test_d1_05
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22, $33, $44
@body:
    ; Wait for the top of vblank so the starting line is known, then run a count-0 transfer.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$08
    sta $4300         ; A->B, fixed source, mode 0
    lda #$22
    sta $4301         ; B-bus = $2122 (CGDATA): harmless, and rebuilt before any scene
    stz $2121         ; CGADD = 0
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302
    sep #$20
    .a8
    phk
    pla
    sta $4304
    rep #$30
    .a16
    .i16
    ldx #$0000
    stx $4305         ; count = 0, which means 65536
    sep #$20
    .a8
    jsr wait_vblank   ; start from a known line
    lda #$01
    sta $420B
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    sta f:$7E00B0     ; where the transfer left the V counter
    ; record slot 110: D1.05 V counter after a count-0 DMA
    sta f:$7EE2DC
    ; The landing line depends on FRAME LENGTH, so measure that rather than assume it: 384
    ; lines past line 225 is line 85 of the next NTSC frame and line 297 of the next PAL one.
    ; Measured, not read from the region bit — whose position B2.10 had to settle, and which a
    ; frame-length test must not lean on.
    sep #$20
    .a8
    stz $2133         ; SETINI: no interlace, which would add a line
    jsr wait_vblank
    jsr wait_vblank   ; a settled frame
    rep #$30
    .a16
    .i16
    lda #$0000
    sta f:$7E0124     ; running maximum
@fh_loop:
    sep #$20
    .a8
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    cmp f:$7E0124
    bcc :+
    sta f:$7E0124
    :
    cmp #100          ; below 100 means the counter wrapped into the next frame
    bcs @fh_loop
    lda f:$7E0124
    ; Named labels, not anonymous ones: assert_a16_range emits its own `:` labels, so a `bne :+`
    ; written across one lands INSIDE the assertion rather than after it. That cost a debugging
    ; round here, with the branch silently taking the wrong arm.
    cmp #311
    bne @ntsc
    lda f:$7E00B0
    cmp #$0113
    bcs :+
    jmp @fail1
  :
    cmp #$0141
    bcc :+
    jmp @fail1
  :
    bra @done
@ntsc:
    lda f:$7E00B0
    cmp #$003C
    bcs :+
    jmp @fail2
  :
    cmp #$006F
    bcc :+
    jmp @fail2
  :
@done:
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; on PAL a count-0 DMA did not take ~384 scanlines, so it did not transfer 65536 bytes
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; on NTSC a count-0 DMA did not take ~384 scanlines, so it did not transfer 65536 bytes
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; D1.09 — WRAM->$2180 no-write
; provenance: Documented (fullsnes: "does not cause a write to occur")
.proc test_d1_09
    .a16
    .i16
    ; Seed the destination, then try to DMA WRAM->$2180 over it. Nothing must change.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$5A
    sta f:$7E0C00
    sta f:$7E0C01
    lda #$00
    sta $2181
    lda #$0C
    sta $2182
    stz $2183         ; WMADD = $7E:0C00 — the destination
    stz $4300         ; A->B, increment, mode 0
    lda #$80
    sta $4301         ; B-bus = $2180
    rep #$30
    .a16
    .i16
    ldx #$0D00
    stx $4302
    sep #$20
    .a8
    lda #$7E
    sta $4304         ; A-bus = $7E:0D00, i.e. WRAM
    rep #$30
    .a16
    .i16
    ldx #$0002
    stx $4305
    sep #$20
    .a8
    lda #$01
    sta $420B
    rep #$30
    .a16
    .i16
    lda f:$7E0C00
    cmp #$5A5A
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; a WRAM->$2180 DMA wrote to WRAM; that transfer must perform no write at all
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; D2.03 — HDMA line-count byte
; provenance: Documented (SNESdev Wiki, HDMA; fullsnes)
.proc test_d2_03
    .a16
    .i16
    bra @body
@table:
    .byte $03, $11    ; non-repeat, 3 lines: one write of $11 to CGDATA
    .byte $04, $22    ; non-repeat, 4 lines: one write of $22, completing the colour word
    .byte $00         ; terminate
@body:
    ; Point HDMA channel 0 at $2180 with WMADD in WRAM, run one frame, then read the trail.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sep #$20
    .a8
    ; Clear the landing page so a trailing zero means HDMA stopped, not that it never started.
    rep #$30
    .a16
    .i16
    ldx #$0000
@clear:
    sep #$20
    .a8
    lda #$00
    sta f:$7E0A00,x
    rep #$30
    .a16
    .i16
    inx
    cpx #$0010
    bne @clear
    sep #$20
    .a8
    stz $420C         ; HDMA off while it is being programmed
    lda #$00
    sta $2181
    lda #$0A
    sta $2182
    stz $2183         ; WMADD = $7E:0A00
    stz $4300         ; A->B, direct table, mode 0 (one byte per transfer)
    lda #$80
    sta $4301         ; B-bus = $2180
    rep #$30
    .a16
    .i16
    ldx #@table
    stx $4302
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; table address = this bank
    ; Arm during vblank: enabling HDMA mid-frame is its own erratum (D2.09), and this test is
    ; not about that. The channel initialises at the top of the next frame.
    jsr wait_vblank
    lda #$01
    sta $420C         ; HDMAEN channel 0
    jsr wait_vblank   ; let the whole active display run
    stz $420C         ; disarm before reading, so nothing moves under the checks
    ; Two non-repeat entries: exactly two bytes, then nothing.
    rep #$30
    .a16
    .i16
    lda f:$7E0A00
    cmp #$2211
    beq :+
    jmp @fail1
  :
    lda f:$7E0A02
    cmp #$0000
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the two non-repeat HDMA entries did not write exactly $11 then $22
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; HDMA kept writing after the $00 terminator
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; D2.04 — HDMA repeat flag
; provenance: Documented (SNESdev Wiki, HDMA; fullsnes)
.proc test_d2_04
    .a16
    .i16
    bra @body
@table:
    .byte $83, $11, $22, $33   ; repeat, 3 lines: one write per line
    .byte $82, $44, $55        ; repeat, 2 lines
    .byte $00                  ; terminate
@body:
    ; Same setup as D2.03; only the table's bit 7 differs.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    sep #$20
    .a8
    ; Clear the landing page so a trailing zero means HDMA stopped, not that it never started.
    rep #$30
    .a16
    .i16
    ldx #$0000
@clear:
    sep #$20
    .a8
    lda #$00
    sta f:$7E0B00,x
    rep #$30
    .a16
    .i16
    inx
    cpx #$0010
    bne @clear
    sep #$20
    .a8
    stz $420C         ; HDMA off while it is being programmed
    lda #$00
    sta $2181
    lda #$0B
    sta $2182
    stz $2183         ; WMADD = $7E:0B00
    stz $4300         ; A->B, direct table, mode 0 (one byte per transfer)
    lda #$80
    sta $4301         ; B-bus = $2180
    rep #$30
    .a16
    .i16
    ldx #@table
    stx $4302
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; table address = this bank
    ; Arm during vblank: enabling HDMA mid-frame is its own erratum (D2.09), and this test is
    ; not about that. The channel initialises at the top of the next frame.
    jsr wait_vblank
    lda #$01
    sta $420C         ; HDMAEN channel 0
    jsr wait_vblank   ; let the whole active display run
    stz $420C         ; disarm before reading, so nothing moves under the checks
    ; Five repeat lines: five bytes in order, then nothing.
    rep #$30
    .a16
    .i16
    lda f:$7E0B00
    cmp #$2211
    beq :+
    jmp @fail1
  :
    lda f:$7E0B02
    cmp #$4433
    beq :+
    jmp @fail2
  :
    lda f:$7E0B04
    and #$00FF
    cmp #$0055
    beq :+
    jmp @fail3
  :
    lda f:$7E0B05
    and #$00FF
    cmp #$0000
    beq :+
    jmp @fail4
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; repeat bytes 0-1 are wrong
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; repeat bytes 2-3 are wrong
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; repeat byte 4 is wrong
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
@fail4:
    ; HDMA wrote a sixth byte; the repeat counts total five lines
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jml test_restore
.endproc

; D2.07 — HDMA preempts GP-DMA
; provenance: Documented (SNESdev Wiki, HDMA; anomie's timing doc; fullsnes)
.proc test_d2_07
    .a16
    .i16
    bra @body
@table:
    .byte $03, $11    ; non-repeat, 3 lines: one write of $11
    .byte $04, $22    ; non-repeat, 4 lines: one write of $22
    .byte $00         ; terminate
@body:
    rep #$30
    .a16
    .i16
    phk
    plb
    ; HDMA writes CGRAM, NOT $2180. Both HDMA and the GP-DMA would otherwise go through the
    ; WRAM data port, which has a single shared WMADD -- they would interleave into each
    ; other's destination and neither result would mean anything. That is what the first
    ; version of this test did, and its trail simply never appeared.
    sep #$20
    .a8
    lda #$80
    sta $2121         ; CGADD = $80, well clear of the palettes the scenes bless
    stz $420C
    stz $4300         ; A->B, direct table, mode 0
    lda #$22
    sta $4301         ; B-bus = $2122 (CGDATA)
    rep #$30
    .a16
    .i16
    ldx #@table
    stx $4302
    sep #$20
    .a8
    phk
    pla
    sta $4304
    ; GP-DMA channel 1: 4 KiB of ROM through the WRAM port at $7E:4000.
    lda #$00
    sta $2181
    lda #$40
    sta $2182
    stz $2183         ; WMADD = $7E:4000
    stz $4310         ; A->B, increment, mode 0
    lda #$80
    sta $4311         ; B-bus = $2180
    rep #$30
    .a16
    .i16
    lda #$8000
    sta $4312         ; A-bus source $00:8000
    sep #$20
    .a8
    stz $4314         ; source bank $00
    rep #$30
    .a16
    .i16
    lda #$1000
    sta $4315         ; 4096 bytes
    ; Arm HDMA in vblank, then start the GP-DMA so it runs THROUGH active display. A transfer
    ; confined to vblank is never preempted and this test would assert nothing.
    sep #$20
    .a8
    jsr wait_vblank
    lda #$01
    sta $420C         ; HDMAEN channel 0
    lda #$02
    sta $420B         ; run channel 1
    jsr wait_vblank   ; let the rest of the frame, and its HDMA, complete
    stz $420C         ; disarm before reading
    ; Half one: HDMA actually ran. Without this the transfer check below is satisfied just as
    ; well by a core that never preempted anything. Read CGRAM back at the index the table
    ; wrote: $2121 selects the word, then $213B reads low then high.
    lda #$80
    sta $2121
    lda $213B
    sta f:$7E0A04
    lda $213B
    sta f:$7E0A05
    rep #$20
    .a16
    lda f:$7E0A04
    and #$7FFF        ; CGRAM is 15-bit; bit 15 reads back as open bus
    cmp #$2211
    beq :+
    jmp @fail1
  :
    ; Half two: the paused transfer resumed and ran to completion. The channel's own registers
    ; say so without needing the destination read back: DAS counts down to zero and A1T ends
    ; at source + length. A core that resumed short leaves both short.
    lda $4315
    cmp #$0000
    beq :+
    jmp @fail2
  :
    lda $4312
    cmp #$9000
    beq :+
    jmp @fail3
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the HDMA trail is absent — no preemption happened, so the transfer check proves nothing
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; channel 1's byte count did not reach zero — the GP-DMA resumed short after preemption
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
@fail3:
    ; channel 1's source address did not advance the full 4096 bytes
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jml test_restore
.endproc

; D1.14 — $2180 B->A does write
; provenance: Documented (fullsnes: $2180->WRAM writes, but the value written is invalid)
.proc test_d1_14
    .a16
    .i16
    ; Both destinations, seeded differently. Whatever invalid value the write deposits, it is
    ; the same for both transfers -- so equal results mean a write, unequal means none.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$00
    sta f:$7E0C10
    lda #$FF
    sta f:$7E0C11
    ; WMADD points somewhere harmless: this direction reads no WRAM, but the port still has an
    ; address and leaving it where a previous test left it would be sloppy rather than wrong.
    lda #$00
    sta $2181
    lda #$0D
    sta $2182
    stz $2183         ; WMADD = $7E:0D00
    ; --- transfer 1: $2180 -> $7E:0C10 ---
    lda #$80
    sta $4300         ; bit 7 = B->A, mode 0
    lda #$80
    sta $4301         ; B-bus = $2180
    rep #$30
    .a16
    .i16
    lda #$0C10
    sta $4302
    sep #$20
    .a8
    lda #$7E
    sta $4304         ; A-bus = $7E:0C10
    rep #$30
    .a16
    .i16
    lda #$0001
    sta $4305         ; one byte
    sep #$20
    .a8
    lda #$01
    sta $420B
    ; --- transfer 2: the same, into the other seed ---
    rep #$30
    .a16
    .i16
    lda #$0C11
    sta $4302
    sep #$20
    .a8
    lda #$7E
    sta $4304
    rep #$30
    .a16
    .i16
    lda #$0001
    sta $4305
    sep #$20
    .a8
    lda #$01
    sta $420B
    ; Equal means a write occurred in both; unequal means the seeds survived and it did not.
    lda f:$7E0C10
    sta f:$7E0C12
    lda f:$7E0C11
    cmp f:$7E0C12
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; $2180 as a DMA source performed no write — both destinations still hold their seeds
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; D1.11 — DMA power-on state
; provenance: Corroborated (fullsnes register table and the SNESdev DMA-registers page agree independently; ares and bsnes default every channel field to match)
.proc test_d1_11
    .a16
    .i16
    ; AND the eleven agreed bytes together: all $FF gives $FF, and any other value cannot.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$FF
    and f:V_PO_DMA+0  ; $4300 DMAP
    and f:V_PO_DMA+1  ; $4301 BBAD
    and f:V_PO_DMA+2  ; $4302 A1T low
    and f:V_PO_DMA+3  ; $4303 A1T high
    ; +4 ($4304, the A1T bank) is skipped: SNESdev says $FF, fullsnes says unspecified.
    and f:V_PO_DMA+5  ; $4305 DAS low
    and f:V_PO_DMA+6  ; $4306 DAS high
    and f:V_PO_DMA+7  ; $4307 DASB
    and f:V_PO_DMA+8  ; $4308 A2A low
    and f:V_PO_DMA+9  ; $4309 A2A high
    and f:V_PO_DMA+10 ; $430A NLTR
    and f:V_PO_DMA+11 ; $430B unused/scratch
    cmp #$FF
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; a DMA channel register did not power on as $FF (Heian Fuuunden depends on this)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; D1.08 — Invalid A-bus (golden)
; provenance: Contested (the errata names the ranges invalid but does not specify what is read instead; the substitute is open bus, whose content is core-specific and time-dependent)
.proc test_d1_08
    .a16
    .i16
    ; Channel 1 reads A-bus $00:4300 -- channel 0's DMAP, never armed here -- into WRAM through
    ; $2180. Run twice with the probe register holding different values.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $420C         ; no HDMA: nothing else may touch the channels mid-test
    stz $4310         ; A->B, increment, mode 0
    lda #$80
    sta $4311         ; B-bus = $2180
    sep #$20
    .a8
    stz $4314         ; A-bus bank $00
    ; --- run 1: probe register = $53 ---
    lda #$53
    sta $4300
    lda #$00
    sta $2181
    lda #$0E
    sta $2182
    stz $2183         ; WMADD = $7E:0E00
    rep #$30
    .a16
    .i16
    lda #$4300
    sta $4312
    lda #$0001
    sta $4315
    sep #$20
    .a8
    lda #$02
    sta $420B
    ; --- run 2: probe register = $A5, destination one byte along ---
    lda #$A5
    sta $4300
    lda #$01
    sta $2181
    lda #$0E
    sta $2182
    stz $2183         ; WMADD = $7E:0E01
    rep #$30
    .a16
    .i16
    lda #$4300
    sta $4312
    lda #$0001
    sta $4315
    sep #$20
    .a8
    lda #$02
    sta $420B
    ; Record both bytes: they are the whole content of this row and the reason it is golden.
    rep #$20
    .a16
    lda f:$7E0E00
    and #$00FF
    ; record slot 122: D1.08 run 1 byte
    sta f:$7EE2F4
    lda f:$7E0E01
    and #$00FF
    ; record slot 123: D1.08 run 2 byte
    sta f:$7EE2F6
    ; Variant 1 = neither run held the probe value; variant 2 = the range was read after all.
    sep #$20
    .a8
    lda f:$7E0E00
    cmp #$53
    beq @sawit
    lda f:$7E0E01
    cmp #$A5
    beq @sawit
    lda #$03
    sta f:$7EE010
    jml test_restore
    @sawit:
    lda #$05
    sta f:$7EE010
    jml test_restore
.endproc

; D1.03 — DMA startup overhead
; provenance: Documented (SNESdev Wiki, DMA timing; fullsnes)
.proc test_d1_03
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22, $33, $44
@body:
    ; A one-byte transfer: almost all of what this measures is overhead.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$08
    sta $4300         ; fixed source, mode 0
    lda #$22
    sta $4301         ; CGDATA — harmless, and rebuilt before any scene
    stz $2121
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302         ; A-bus address = this test's data table
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; A-bus bank = this bank
    rep #$30
    .a16
    .i16
    ldx #$0001
    stx $4305         ; byte count
    sep #$20
    .a8
    jsr hv_begin
    lda #$01
    sta $420B
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 111: D1.03 one-byte DMA, absolute (dots)
    sta f:$7EE2DE
    sep #$20
    .a8
    lda #$01
    sta f:V_TEST_RESULT   ; golden: the number is in the measurement channel
    jml test_restore
.endproc

; D1.04 — DMA channel priority
; provenance: Documented (SNESdev Wiki, DMA; fullsnes)
.proc test_d1_04
    .a16
    .i16
    bra @body
@data:
    .byte $11, $22
@body:
    ; Both channels write one byte to $2180. WMADD advances across both, so the pair in WRAM
    ; is the execution order written down.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$00
    sta $2181
    lda #$0E
    sta $2182
    stz $2183         ; WMADD = $7E:0E00
    ; --- channel 0: sources $11 ---
    lda #$08
    sta $4300         ; A->B, fixed, mode 0
    lda #$80
    sta $4301
    rep #$30
    .a16
    .i16
    ldx #@data
    stx $4302
    sep #$20
    .a8
    phk
    pla
    sta $4304
    rep #$30
    .a16
    .i16
    ldx #$0001
    stx $4305
    ; --- channel 1: sources $22 ---
    sep #$20
    .a8
    lda #$08
    sta $4310
    lda #$80
    sta $4311
    rep #$30
    .a16
    .i16
    ldx #(@data + 1)
    stx $4312
    sep #$20
    .a8
    phk
    pla
    sta $4314
    rep #$30
    .a16
    .i16
    ldx #$0001
    stx $4315
    ; Start both in ONE write — which is the whole point; two writes would impose the order.
    sep #$20
    .a8
    lda #$03
    sta $420B
    rep #$30
    .a16
    .i16
    lda f:$7E0E00
    cmp #$2211
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; the channels did not run in ascending order (expected $11 from ch0 then $22 from ch1)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; D2.05 — HDMA indirect mode
; provenance: Documented (SNESdev Wiki, HDMA; fullsnes)
.proc test_d2_05
    .a16
    .i16
    bra @body
@table:
    .byte $02
    .addr @ind1      ; indirect: the DATA lives at this address, not here
    .byte $02
    .addr @ind2
    .byte $00        ; terminate
@ind1:
    .byte $77
@ind2:
    .byte $88
@body:
    ; Same $2180 trick as D2.03/D2.04, with DMAP bit 6 set and $4307 naming the data bank.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $420C
    ; Clear the landing page first.
    rep #$30
    .a16
    .i16
    ldx #$0000
@clear:
    sep #$20
    .a8
    lda #$00
    sta f:$7E0F00,x
    rep #$30
    .a16
    .i16
    inx
    cpx #$0010
    bne @clear
    sep #$20
    .a8
    lda #$00
    sta $2181
    lda #$0F
    sta $2182
    stz $2183         ; WMADD = $7E:0F00
    lda #$40
    sta $4300         ; A->B, INDIRECT, mode 0
    lda #$80
    sta $4301         ; B-bus = $2180
    rep #$30
    .a16
    .i16
    ldx #@table
    stx $4302
    sep #$20
    .a8
    phk
    pla
    sta $4304         ; table bank
    phk
    pla
    sta $4307         ; indirect DATA bank
    jsr wait_vblank
    lda #$01
    sta $420C
    jsr wait_vblank
    stz $420C
    rep #$30
    .a16
    .i16
    lda f:$7E0F00
    cmp #$8877
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; indirect HDMA did not fetch through the pointers (a core ignoring bit 6 writes the pointer bytes instead)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

; D2.06 — HDMA $4308/$430A state
; provenance: Documented (SNESdev Wiki, HDMA registers; fullsnes)
.proc test_d2_06
    .a16
    .i16
    bra @body
@table:
    .byte $02, $11
    .byte $00
@body:
    ; Run one frame of HDMA to $2180, then read the channel's working registers.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $420C
    lda #$00
    sta $2181
    lda #$10
    sta $2182
    stz $2183         ; WMADD = $7E:1000
    stz $4300
    lda #$80
    sta $4301
    rep #$30
    .a16
    .i16
    ldx #@table
    stx $4302
    sep #$20
    .a8
    phk
    pla
    sta $4304
    jsr wait_vblank
    lda #$01
    sta $420C
    jsr wait_vblank
    stz $420C
    lda $430A
    cmp #$00
    beq :+
    jmp @fail1
  :
    ; $4308/09 must have advanced past the table's start — it is a walking pointer.
    rep #$30
    .a16
    .i16
    lda $4308
    sec
    sbc #@table
    cmp #$0001
    bcs :+
    jmp @fail2
  :
    cmp #$0011
    bcc :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; $430A does not hold the $00 terminator after the table ran out
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; $4308/09 did not advance past the table start; it is a working pointer, not a copy
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

; A5.S01 — Sweep: CLC
; provenance: Documented (WDC/GTE/VLSI instruction-operation tables agree; docs/accuracysnes-timing-oracle.md)
.proc test_a5_s01
    .a16
    .i16
    ; CLC — expect 14 clocks per iteration.
    ; Derivation: 2 cycles, 1 access (opcode fetch).
    ; Baseline is 1 NOP(s) per iteration so the fetch overhead cancels; the difference is
    ; the instruction's own extra cost. Raw spans are recorded so a failure can be inspected.
    rep #$30
    .a16
    .i16
    phk
    plb
    ; The sandbox establishes m=1 AND x=1, the state every expectation in this table is stated
    ; at. `sep #$20` alone narrows only the accumulator and leaves the index registers 16-bit,
    ; which silently changes the cost of every index-register instruction: LDX #imm becomes a
    ; 3-byte 3-cycle fetch, and PHX/PLX push and pull two bytes instead of one. Both showed up
    ; as failures the first time this ran — the sandbox has to match its own preconditions.
    sep #$30
    .a8
    .i8
    ; Two distinct preconditions, easy to conflate: `sep #$30` sets the m and x FLAGS, making
    ; the accumulator and index registers 8-bit — that is what every expectation in the table
    ; is derived at. `ldx #$00` then sets the X REGISTER to zero, so the indexed entries have a
    ; defined index that cannot cross a page. The baseline is NOPs, which touch neither.
    ldx #$00
    ; --- baseline ---
    jsr hv_begin
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0096
    ; record slot 8: baseline NOPs, absolute
    sta f:$7EE210
    ; --- the opcode under test ---
    sep #$30
    .a8
    .i8
    jsr hv_begin
    clc
    clc
    clc
    clc
    clc
    clc
    clc
    clc
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0096
    ; record slot 9: measured minus baseline
    sta f:$7EE212
    cmp #$0000
    bcs :+
    jmp @fail1
  :
    cmp #$0003
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jml test_restore
@fail1:
    ; measured cost disagrees with the manufacturer tables
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
.endproc

