    sep #$20
    .a8
    lda APUIO0
    cmp #$5A
    beq @ran
    rep #$30
    .a16
    .i16
    inx
    cpx #$8000
    bne @wait
    bra @timeout
@ran:
    ; Copy the answers out BEFORE releasing the program: once it jumps to the IPL, the boot ROM
    ; overwrites ports 0 and 1 with its $AA/$BB announcement.
    sep #$20
    .a8
    lda APUIO1
    sta f:$7E0100
    lda APUIO2
    sta f:$7E0101
    lda APUIO3
    sta f:$7E0102
