    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jml test_restore
@fail2:
    ; the second read of $FD was non-zero — reading a timer counter must clear it
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jml test_restore
.endproc

